# SQL Injection Demo - Interactive Learning Tool

Here's a comprehensive, self-contained HTML demo that clearly illustrates the difference between vulnerable and safe query approaches:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>SQL Injection Learning Demo</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background: #0f1117;
            color: #e0e0e0;
            min-height: 100vh;
            padding: 20px;
        }

        .header {
            text-align: center;
            padding: 30px 20px;
            background: linear-gradient(135deg, #1a1a2e, #16213e);
            border-radius: 12px;
            margin-bottom: 30px;
            border: 1px solid #2a2a4a;
        }

        .header h1 {
            font-size: 2rem;
            color: #7c83fd;
            margin-bottom: 10px;
        }

        .header p {
            color: #9090b0;
            font-size: 1rem;
            max-width: 700px;
            margin: 0 auto;
            line-height: 1.6;
        }

        .warning-banner {
            background: linear-gradient(135deg, #2d1b00, #3d2500);
            border: 1px solid #ff8c00;
            border-radius: 8px;
            padding: 15px 20px;
            margin-bottom: 25px;
            display: flex;
            align-items: center;
            gap: 12px;
        }

        .warning-banner .icon {
            font-size: 1.5rem;
            flex-shrink: 0;
        }

        .warning-banner p {
            color: #ffb347;
            font-size: 0.9rem;
            line-height: 1.5;
        }

        .database-panel {
            background: #1a1a2e;
            border: 1px solid #2a2a4a;
            border-radius: 12px;
            padding: 20px;
            margin-bottom: 25px;
        }

        .database-panel h2 {
            color: #7c83fd;
            margin-bottom: 15px;
            font-size: 1.1rem;
            display: flex;
            align-items: center;
            gap: 8px;
        }

        .db-table {
            width: 100%;
            border-collapse: collapse;
            font-size: 0.85rem;
        }

        .db-table th {
            background: #252545;
            color: #9090d0;
            padding: 10px 14px;
            text-align: left;
            border: 1px solid #3a3a5a;
            font-weight: 600;
            text-transform: uppercase;
            letter-spacing: 0.5px;
            font-size: 0.75rem;
        }

        .db-table td {
            padding: 9px 14px;
            border: 1px solid #2a2a4a;
            color: #c0c0e0;
        }

        .db-table tr:nth-child(even) td {
            background: #1e1e38;
        }

        .db-table tr:hover td {
            background: #252550;
        }

        .hidden-row td {
            color: #ff6b6b !important;
            background: #2d1a1a !important;
        }

        .hidden-badge {
            background: #ff4444;
            color: white;
            font-size: 0.65rem;
            padding: 2px 6px;
            border-radius: 4px;
            margin-left: 6px;
            font-weight: bold;
        }

        .demo-grid {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 20px;
            margin-bottom: 25px;
        }

        @media (max-width: 900px) {
            .demo-grid {
                grid-template-columns: 1fr;
            }
        }

        .demo-panel {
            background: #1a1a2e;
            border-radius: 12px;
            padding: 20px;
            border: 2px solid transparent;
        }

        .demo-panel.vulnerable {
            border-color: #ff4444;
        }

        .demo-panel.safe {
            border-color: #44ff88;
        }

        .panel-header {
            display: flex;
            align-items: center;
            gap: 10px;
            margin-bottom: 18px;
        }

        .panel-badge {
            padding: 4px 12px;
            border-radius: 20px;
            font-size: 0.75rem;
            font-weight: bold;
            text-transform: uppercase;
            letter-spacing: 0.5px;
        }

        .badge-vulnerable {
            background: #ff444420;
            color: #ff6666;
            border: 1px solid #ff4444;
        }

        .badge-safe {
            background: #44ff8820;
            color: #44ff88;
            border: 1px solid #44ff88;
        }

        .panel-title {
            font-size: 1rem;
            font-weight: 600;
            color: #e0e0e0;
        }

        .search-group {
            margin-bottom: 15px;
        }

        .search-group label {
            display: block;
            font-size: 0.8rem;
            color: #9090b0;
            margin-bottom: 6px;
            text-transform: uppercase;
            letter-spacing: 0.5px;
        }

        .search-input {
            width: 100%;
            padding: 10px 14px;
            background: #0f1117;
            border: 1px solid #3a3a5a;
            border-radius: 8px;
            color: #e0e0e0;
            font-size: 0.95rem;
            font-family: 'Courier New', monospace;
            transition: border-color 0.2s;
        }

        .search-input:focus {
            outline: none;
            border-color: #7c83fd;
        }

        .search-btn {
            width: 100%;
            padding: 10px;
            border: none;
            border-radius: 8px;
            font-size: 0.95rem;
            font-weight: 600;
            cursor: pointer;
            transition: all 0.2s;
            margin-bottom: 15px;
        }

        .btn-vulnerable {
            background: linear-gradient(135deg, #cc2200, #ff4444);
            color: white;
        }

        .btn-vulnerable:hover {
            background: linear-gradient(135deg, #ff4444, #ff6666);
            transform: translateY(-1px);
        }

        .btn-safe {
            background: linear-gradient(135deg, #006633, #44ff88);
            color: #001a0d;
        }

        .btn-safe:hover {
            background: linear-gradient(135deg, #44ff88, #66ffaa);
            transform: translateY(-1px);
        }

        .query-display {
            background: #0a0a15;
            border-radius: 8px;
            padding: 12px 14px;
            margin-bottom: 15px;
            border: 1px solid #2a2a4a;
        }

        .query-display .label {
            font-size: 0.7rem;
            color: #6060a0;
            text-transform: uppercase;
            letter-spacing: 0.5px;
            margin-bottom: 6px;
        }

        .query-display .query-text {
            font-family: 'Courier New', monospace;
            font-size: 0.82rem;
            line-height: 1.5;
            word-break: break-all;
        }

        .query-vulnerable {
            color: #ff9999;
        }

        .query-safe {
            color: #99ffcc;
        }

        .highlight-injection {
            background: #ff000030;
            border: 1px solid #ff4444;
            border-radius: 3px;
            padding: 0 2px;
            color: #ff6666;
        }

        .highlight-param {
            background: #00ff8830;
            border: 1px solid #44ff88;
            border-radius: 3px;
            padding: 0 2px;
            color: #44ff88;
        }

        .results-area {
            min-height: 100px;
        }

        .results-label {
            font-size: 0.75rem;
            color: #6060a0;
            text-transform: uppercase;
            letter-spacing: 0.5px;
            margin-bottom: 8px;
        }

        .result-card {
            background: #0f1117;
            border: 1px solid #2a2a4a;
            border-radius: 8px;
            padding: 10px 14px;
            margin-bottom: 8px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            font-size: 0.85rem;
        }

        .result-card .product-name {
            font-weight: 600;
            color: #c0c0e0;
        }

        .result-card .product-meta {
            color: #7070a0;
            font-size: 0.78rem;
        }

        .result-card .product-price {
            color: #7c83fd;
            font-weight: 600;
        }

        .result-card.leaked {
            border-color: #ff4444;
            background: #1a0a0a;
        }

        .result-card.leaked .product-name {
            color: #ff9999;
        }

        .leaked-badge {
            background: #ff444420;
            color: #ff6666;
            border: 1px solid #ff4444;
            font-size: 0.65rem;
            padding: 2px 8px;
            border-radius: 4px;
            font-weight: bold;
        }

        .no-results {
            text-align: center;
            padding: 20px;
            color: #5050a0;
            font-size: 0.85rem;
        }

        .status-bar {
            display: flex;
            align-items: center;
            gap: 8px;
            padding: 8px 12px;
            border-radius: 6px;
            margin-bottom: 10px;
            font-size: 0.8rem;
        }

        .status-danger {
            background: #2d0a0a;
            border: 1px solid #ff4444;
            color: #ff8888;
        }

        .status-success {
            background: #0a2d1a;
            border: 1px solid #44ff88;
            color: #44ff88;
        }

        .status-neutral {
            background: #1a1a2e;
            border: 1px solid #3a3a5a;
            color: #7070a0;
        }

        .injection-presets {
            margin-bottom: 25px;
            background: #1a1a2e;
            border: 1px solid #2a2a4a;
            border-radius: 12px;
            padding: 20px;
        }

        .injection-presets h2 {
            color: #7c83fd;
            font-size: 1.1rem;
            margin-bottom: 6px;
        }

        .injection-presets p {
            color: #7070a0;
            font-size: 0.85rem;
            margin-bottom: 15px;
        }

        .preset-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
            gap: 10px;
        }

        .preset-btn {
            background: #0f1117;
            border: 1px solid #3a3a5a;
            border-radius: 8px;
            padding: 12px 14px;
            cursor: pointer;
            text-align: left;
            transition: all 0.2s;
            color: #e0e0e0;
        }

        .preset-btn:hover {
            border-color: #7c83fd;
            background: #16162a;
        }

        .preset-btn .preset-code {
            font-family: 'Courier New', monospace;
            font-size: 0.82rem;
            color: #ff9999;
            display: block;
            margin-bottom: 4px;
        }

        .preset-btn .preset-desc {
            font-size: 0.75rem;
            color: #7070a0;
        }

        .explanation-panel {
            background: #1a1a2e;
            border: 1px solid #2a2a4a;
            border-radius: 12px;
            padding: 25px;
            margin-bottom: 25px;
        }

        .explanation-panel h2 {
            color: #7c83fd;
            font-size: 1.2rem;
            margin-bottom: 20px;
        }

        .explanation-grid {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 20px;
        }

        @media (max-width: 700px) {
            .explanation-grid {
                grid-template-columns: 1fr;
            }
        }

        .explanation-card {
            background: #0f1117;
            border-radius: 10px;
            padding: 18px;
        }

        .explanation-card.danger {
            border: 1px solid #ff444440;
        }

        .explanation-card.success {
            border: 1px solid #44ff8840;
        }

        .explanation-card h3 {
            font-size: 0.95rem;
            margin-bottom: 12px;
            display: flex;
            align-items: center;
            gap: 8px;
        }

        .explanation-card.danger h3 {
            color: #ff8888;
        }

        .explanation-card.success h3 {
            color: #44ff88;
        }

        .explanation-card ul {
            list-style: none;
            padding: 0;
        }

        .explanation-card ul li {
            font-size: 0.82rem;
            color: #9090b0;
            padding: 6px 0;
            border-bottom: 1px solid #1e1e38;
            line-height: 1.5;
            display: flex;
            gap: 8px;
        }

        .explanation-card ul li:last-child {
            border-bottom: none;
        }

        .explanation-card ul li .bullet {
            flex-shrink: 0;
        }

        .how-it-works {
            background: #0f1117;
            border: 1px solid #2a2a4a;
            border-radius: 10px;
            padding: 18px;
            margin-top: 20px;
        }

        .how-it-works h3 {
            color: #7c83fd;
            font-size: 0.95rem;
            margin-bottom: 12px;
        }

        .step {
            display: flex;
            gap: 12px;
            margin-bottom: 14px;
            align-items: flex-start;
        }

        .step-num {
            background: #7c83fd20;
            border: 1px solid #7c83fd;
            color: #7c83fd;
            width: 24px;
            height: 24px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 0.75rem;
            font-weight: bold;
            flex-shrink: 0;
        }

        .step-text {
            font-size: 0.83rem;
            color: #9090b0;
            line-height: 1.6;
            padding-top: 2px;
        }

        .step-text code {
            font-family: 'Courier New', monospace;
            background: #1a1a3a;
            padding: 1px 5px;
            border-radius: 3px;
            color: #a0a8ff;
            font-size: 0.82rem;
        }

        .count-badge {
            display: inline-block;
            background: #7c83fd20;
            color: #7c83fd;
            border: 1px solid #7c83fd40;
            border-radius: 12px;
            padding: 2px 10px;
            font-size: 0.75rem;
            margin-bottom: 8px;
        }

        .sync-note {
            background: #16213e;
            border: 1px solid #3a3a6a;
            border-radius: 8px;
            padding: 10px 14px;
            font-size: 0.8rem;
            color: #7070a0;
            text-align: center;
            margin-bottom: 20px;
        }

        .sync-note span {
            color: #7c83fd;
        }
    </style>
</head>
<body>

    <div class="header">
        <h1>🔐 SQL Injection Learning Demo</h1>
        <p>
            An interactive, educational tool showing how SQL injection works and why
            parameterized queries prevent it. All data is simulated in JavaScript —
            no real database or server is involved.
        </p>
    </div>

    <div class="warning-banner">
        <div class="icon">⚠️</div>
        <p>
            <strong>Educational Purpose Only.</strong> This demo simulates SQL injection
            concepts using JavaScript to help developers understand and prevent these
            vulnerabilities. Never attempt SQL injection on real systems without explicit
            written authorization. Unauthorized access is illegal.
        </p>
    </div>

    <!-- Database Viewer -->
    <div class="database-panel">
        <h2>🗄️ Simulated Product Database — <code>products</code> table</h2>
        <p style="color:#6060a0; font-size:0.8rem; margin-bottom:12px;">
            Red rows represent sensitive/hidden records that should never appear in normal search results.
        </p>
        <div style="overflow-x:auto;">
            <table class="db-table" id="dbTable">
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Name</th>
                        <th>Category</th>
                        <th>Price</th>
                        <th>Stock</th>
                        <th>Visibility</th>
                    </tr>
                </thead>
                <tbody id="dbTableBody"></tbody>
            </table>
        </div>
    </div>

    <!-- Injection Presets -->
    <div class="injection-presets">
        <h2>🧪 Try These Injection Inputs</h2>
        <p>Click any preset to load it into both search fields and see how each mode responds differently.</p>
        <div class="preset-grid" id="presetGrid"></div>
    </div>

    <div class="sync-note">
        💡 Both panels use the <span>same input</span> — type in either field and both update together.
        The difference is entirely in how each mode <span>processes</span> your input.
    </div>

    <!-- Demo Panels -->
    <div class="demo-grid">

        <!-- Vulnerable Panel -->
        <div class="demo-panel vulnerable">
            <div class="panel-header">
                <span class="panel-badge badge-vulnerable">⚠ Vulnerable</span>
                <span class="panel-title">String Concatenation</span>
            </div>

            <div class="search-group">
                <label>Search Products</label>
                <input
                    type="text"
                    class="search-input"
                    id="vulnerableInput"
                    placeholder="e.g. laptop or try: ' OR '1'='1"
                    oninput="syncInputs('vulnerable')"
                />
            </div>

            <button class="search-btn btn-vulnerable" onclick="runVulnerableSearch()">
                🔍 Search (Vulnerable)
            </button>

            <div class="query-display">
                <div class="label">Constructed Query String</div>
                <div class="query-text query-vulnerable" id="vulnerableQuery">
                    Awaiting input...
                </div>
            </div>

            <div id="vulnerableStatus"></div>
            <div class="results-label">Results</div>
            <div class="results-area" id="vulnerableResults">
                <div class="no-results">Run a search to see results</div>
            </div>
        </div>

        <!-- Safe Panel -->
        <div class="demo-panel safe">
            <div class="panel-header">
                <span class="panel-badge badge-safe">✓ Safe</span>
                <span class="panel-title">Parameterized Filtering</span>
            </div>

            <div class="search-group">
                <label>Search Products</label>
                <input
                    type="text"
                    class="search-input"
                    id="safeInput"
                    placeholder="e.g. laptop or try: ' OR '1'='1"
                    oninput="syncInputs('safe')"
                />
            </div>

            <button class="search-btn btn-safe" onclick="runSafeSearch()">
                🔍 Search (Safe)
            </button>

            <div class="query-display">
                <div class="label">Parameterized Query + Bound Value</div>
                <div class="query-text query-safe" id="safeQuery">
                    Awaiting input...
                </div>
            </div>

            <div id="safeStatus"></div>
            <div class="results-label">Results</div>
            <div class="results-area" id="safeResults">
                <div class="no-results">Run a search to see results</div>
            </div>
        </div>

    </div>

    <!-- Explanation -->
    <div class="explanation-panel">
        <h2>📚 How It Works — Why Parameterization Prevents Injection</h2>

        <div class="explanation-grid">
            <div class="explanation-card danger">
                <h3>⚠️ Vulnerable: String Concatenation</h3>
                <ul>
                    <li>
                        <span class="bullet">🔴</span>
                        User input is directly embedded into the query string before evaluation.
                    </li>
                    <li>
                        <span class="bullet">🔴</span>
                        SQL syntax characters like <code>'</code>, <code>--</code>, <code>OR</code>
                        are interpreted as part of the query logic.
                    </li>
                    <li>
                        <span class="bullet">🔴</span>
                        An attacker can close the original string and append new conditions,
                        changing what the query returns.
                    </li>
                    <li>
                        <span class="bullet">🔴</span>
                        Input <code>' OR '1'='1</code> makes the WHERE clause always true,
                        returning every row including hidden ones.
                    </li>
                    <li>
                        <span class="bullet">🔴</span>
                        Real attacks can also DROP tables, exfiltrate data from other tables,
                        or create admin accounts.
                    </li>
                </ul>
            </div>

            <div class="explanation-card success">
                <h3>✅ Safe: Parameterized Queries</h3>
                <ul>
                    <li>
                        <span class="bullet">🟢</span>
                        The query structure is defined first, with a placeholder
                        (<code>?</code> or <code>:param</code>) for user input.
                    </li>
                    <li>
                        <span class="bullet">🟢</span>
                        The database engine receives the query template and the data
                        <em>separately</em> — they are never combined as a string.
                    </li>
                    <li>
                        <span class="bullet">🟢</span>
                        The engine treats the entire input as a literal data value,
                        not as executable SQL syntax.
                    </li>
                    <li>
                        <span class="bullet">🟢</span>
                        <code>' OR '1'='1</code> is searched for literally as a product
                        name — no special SQL meaning is applied.
                    </li>
                    <li>
                        <span class="bullet">🟢</span>
                        No matter what characters the user types, they cannot alter
                        the query's structure or logic.
                    </li>
                </ul>
            </div>
        </div>

        <div class="how-it-works">
            <h3>🔬 Step-by-Step: What Happens with <code>' OR '1'='1</code></h3>

            <div style="display:grid; grid-template-columns:1fr 1fr; gap:20px;">
                <div>
                    <p style="color:#ff8888; font-size:0.8rem; margin-bottom:10px; font-weight:600;">
                        ⚠️ VULNERABLE PATH
                    </p>
                    <div class="step">
                        <div class="step-num">1</div>
                        <div class="step-text">
                            App builds: <code>"SELECT * FROM products WHERE name LIKE '%" + input + "%'"</code>
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">2</div>
                        <div class="step-text">
                            Result string becomes:
                            <code>SELECT * FROM products WHERE name LIKE '%' OR '1'='1%'</code>
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">3</div>
                        <div class="step-text">
                            The <code>OR '1'='1'</code> condition is always true, so
                            the WHERE clause matches every single row.
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">4</div>
                        <div class="step-text">
                            All records are returned — including hidden, admin, and
                            sensitive rows that should never be visible.
                        </div>
                    </div>
                </div>

                <div>
                    <p style="color:#44ff88; font-size:0.8rem; margin-bottom:10px; font-weight:600;">
                        ✅ SAFE PATH
                    </p>
                    <div class="step">
                        <div class="step-num">1</div>
                        <div class="step-text">
                            App sends template: <code>SELECT * FROM products WHERE name LIKE ?</code>
                            — structure is locked in.
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">2</div>
                        <div class="step-text">
                            Input <code>' OR '1'='1</code> is passed as a separate
                            data parameter, wrapped as <code>%' OR '1'='1%</code>.
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">3</div>
                        <div class="step-text">
                            Database treats the entire value as a literal string to
                            match against — SQL keywords have no effect here.
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">4</div>
                        <div class="step-text">
                            No product named <code>' OR '1'='1</code> exists, so
                            zero results are returned. Attack completely neutralized.
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <script>
        // ─────────────────────────────────────────────
        // SIMULATED DATABASE
        // ─────────────────────────────────────────────
        const database = [
            { id: 1,  name: "Laptop Pro 15",        category: "Electronics", price: 1299.99, stock: 45,  hidden: false },
            { id: 2,  name: "Wireless Mouse",        category: "Electronics", price: 29.99,  stock: 200, hidden: false },
            { id: 3,  name: "USB-C Hub",             category: "Electronics", price: 49.99,  stock: 150, hidden: false },
            { id: 4,  name: "Mechanical Keyboard",   category: "Electronics", price: 149.99, stock: 80,  hidden: false },
