            document.getElementById('safeQuery').innerHTML =
                `Template: SELECT * FROM products WHERE (name LIKE <span class="highlight-param">?</span> OR category LIKE <span class="highlight-param">?</span>) AND visible = true\n` +
                `Bound value: <span class="highlight-param">"${escapeHtml(input)}"</span> (treated as literal string data)`;

            // Safe: just do a literal string match — no SQL parsing of input
            const searchTerm = input.toLowerCase().trim();
            const results = database.filter(row =>
                !row.hidden &&
                (
                    row.name.toLowerCase().includes(searchTerm) ||
                    row.category.toLowerCase().includes(searchTerm)
                )
            );

