                /'\s*OR\s*1\s*=\s*1/i,
                /'\s*OR\s*'x'\s*=\s*'x/i,
                /'\s*OR\s*'\w+'\s*=\s*'\w+/i,
                /'\s*OR\s+\w+\s*=\s*\w+/i,
                /OR\s+TRUE/i,
            ];

            const isAlwaysTrue = alwaysTruePatterns.some(p => p.test(input));

            // Detect hidden column targeting
            const targetsHidden = /hidden\s*=\s*true/i.test(input);

            // Detect category injection
            const categoryMatch = input.match(/category\s*=\s*'?([^'"\s]+)/i);

            if (isAlwaysTrue || targetsHidden) {
                // Return ALL rows including hidden — injection succeeded
                return database.map(r => ({ ...r, injected: true }));
            }

            if (categoryMatch) {
                const injectedCategory = categoryMatch[1].toUpperCase();
                return database.filter(row =>
                    row.category.toUpperCase() === injectedCategory ||
                    (!row.hidden && (
                        row.name.toLowerCase().includes(input.split("'")[0].toLowerCase()) ||
                        row.category.toLowerCase().includes(input.split("'")[0].toLowerCase())
                    ))
                ).map(r => ({ ...r, injected: r.hidden }));
            }

            // Normal (non-injected) vulnerable query — still filters hidden
            // but only because the injection didn't trigger
            const searchTerm = input.toLowerCase().trim();
            return database.filter(row =>
                !row.hidden &&
                (
                    row.name.toLowerCase().includes(searchTerm) ||
                    row.category.toLowerCase().includes(searchTerm)
                )
            );
        }

        // ─────────────────────────────────────────────
