<body>

    <div class="header">
        <h1>🔐 SQL Injection Educational Demo</h1>
        <p>
            Learn how SQL injection attacks work and why parameterized queries prevent them.
            This demo simulates database behavior entirely in JavaScript — no real database is used.
        </p>
    </div>

    <div class="warning-banner">
        <div class="icon">⚠️</div>
        <p>
            <strong>Educational Purpose Only.</strong> This demo is designed to help developers
            understand SQL injection so they can write safer code. Never attempt SQL injection
            against real systems you don't own. Always use parameterized queries or prepared
            statements in production code.
        </p>
    </div>

    <!-- Database Viewer -->
    <div class="db-viewer">
        <h3>🗄️ Simulated In-Memory Database</h3>
        <div class="db-tabs">
            <button class="db-tab active" onclick="showTable('products')">products</button>
            <button class="db-tab" onclick="showTable('users')">users (sensitive!)</button>
        </div>
        <div class="db-table-wrapper" id="dbTableDisplay"></div>
        <p class="db-note">💡 Both tables exist in this simulated database. Injection attacks can expose data from ANY table, not just the one being searched.</p>
    </div>

    <!-- Quick Attack Presets -->
    <div class="quick-attacks">
        <h3>⚡ Try These Injection Payloads</h3>
        <p>Click any payload below to auto-fill both search boxes. Watch how the vulnerable version is exploited while the safe version remains protected.</p>
        <div class="attack-buttons" id="attackButtons"></div>
    </div>

    <!-- Main Two-Panel Demo -->
    <div class="main-grid">

        <!-- Vulnerable Panel -->
        <div class="panel">
            <div class="panel-header vulnerable">
                <span style="font-size:1.3rem">💀</span>
                <h2>Vulnerable Version</h2>
                <span class="badge badge-danger">Unsafe</span>
            </div>
            <div class="panel-body">
                <div class="search-group">
                    <label>Search products by name (string concatenation):</label>
                    <div class="search-input-row">
                        <input
                            type="text"
                            id="vulnerableInput"
                            class="search-input vulnerable-input"
                            placeholder='Try: laptop" OR "1"="1'
                            oninput="runBothSearches()"
                        />
                        <button class="btn btn-danger" onclick="runBothSearches()">Search</button>
                    </div>
                </div>

                <div class="query-display vulnerable-query">
                    <div class="query-label">🔴 Constructed "Query" (Vulnerable)</div>
                    <div class="query-text vulnerable-text" id="vulnerableQueryDisplay">
                        Waiting for input...
                    </div>
                </div>

                <div id="vulnerableStatus" class="status-bar status-normal">
                    ℹ️ Enter a search term above
                </div>

                <div class="results-area">
                    <div class="result-count" id="vulnerableCount"></div>
                    <div class="results-label">Results:</div>
                    <div id="vulnerableResults"></div>
                </div>
            </div>
        </div>

        <!-- Safe Panel -->
        <div class="panel">
            <div class="panel-header safe">
                <span style="font-size:1.3rem">🛡️</span>
                <h2>Safe Version</h2>
                <span class="badge badge-safe">Protected</span>
            </div>
            <div class="panel-body">
                <div class="search-group">
                    <label>Search products by name (parameterized filtering):</label>
                    <div class="search-input-row">
                        <input
                            type="text"
                            id="safeInput"
                            class="search-input safe-input"
                            placeholder='Try: laptop" OR "1"="1'
                            oninput="runBothSearches()"
                        />
                        <button class="btn btn-safe" onclick="runBothSearches()">Search</button>
                    </div>
                </div>

                <div class="query-display safe-query">
                    <div class="query-label">🟢 Parameterized "Query" (Safe)</div>
                    <div class="query-text safe-text" id="safeQueryDisplay">
                        Waiting for input...
                    </div>
                </div>

                <div id="safeStatus" class="status-bar status-normal">
                    ℹ️ Enter a search term above
                </div>

                <div class="results-area">
                    <div class="result-count" id="safeCount"></div>
                    <div class="results-label">Results:</div>
                    <div id="safeResults"></div>
                </div>
            </div>
        </div>

    </div>

    <!-- Explanation Section -->
    <div class="explanation">
        <h3>📚 Why Does This Happen?</h3>
        <div class="explanation-grid">
            <div class="explanation-card bad">
                <h4>💀 String Concatenation (Vulnerable)</h4>
                <p>
                    When user input is directly concatenated into a query string, the database
                    (or query engine) cannot distinguish between the developer's intended
                    query structure and the attacker's injected commands. The input becomes
                    part of the query logic itself.
                </p>
                <div class="code-snippet">
<span class="code-bad">// DANGEROUS — Never do this!
const query =
  "SELECT * FROM products " +
  "WHERE name = '" + userInput + "'";

// If userInput = ' OR '1'='1
// Query becomes:
// SELECT * FROM products
// WHERE name = '' OR '1'='1'
// → Returns ALL rows!</span>
                </div>
            </div>
            <div class="explanation-card good">
                <h4>🛡️ Parameterized Queries (Safe)</h4>
                <p>
                    Parameterized queries (also called prepared statements) separate the
                    query structure from the data. The database receives the query template
                    and the parameter value separately. The input is <strong>always treated
                    as data</strong>, never as executable query logic — no matter what it contains.
                </p>
                <div class="code-snippet">
<span class="code-good">// SAFE — Always do this!
const query =
  "SELECT * FROM products " +
  "WHERE name = ?";

// Parameter passed separately:
db.execute(query, [userInput]);

// Even if userInput = ' OR '1'='1
// It's treated as a literal string
// → Returns only exact matches!</span>
                </div>
            </div>
        </div>
    </div>

    <!-- Step by Step -->
    <div class="step-list" style="margin-bottom: 30px;">
        <h3>🧪 Suggested Experiments</h3>
        <div class="steps">
            <div class="step">
                <div class="step-num">1</div>
                <div class="step-text">
                    <strong>Normal search:</strong> Type <code style="color:#a78bfa">laptop</code> — both versions return the same expected results.
                </div>
            </div>
            <div class="step">
                <div class="step-num">2</div>
                <div class="step-text">
                    <strong>Basic bypass:</strong> Type <code style="color:#a78bfa">' OR '1'='1</code> — the vulnerable version returns ALL products because the condition is always true. The safe version finds nothing (no product is literally named that).
                </div>
            </div>
            <div class="step">
                <div class="step-num">3</div>
                <div class="step-text">
                    <strong>UNION attack:</strong> Try the UNION payload from the presets. In the vulnerable version, this merges results from the <em>users</em> table — exposing passwords! The safe version treats it as a plain search string.
                </div>
            </div>
            <div class="step">
                <div class="step-num">4</div>
                <div class="step-text">
                    <strong>Comment trick:</strong> Try <code style="color:#a78bfa">anything' --</code> — the <code style="color:#a78bfa">--</code> comments out the rest of the query in SQL, bypassing additional WHERE conditions. The safe version ignores the comment syntax entirely.
                </div>
            </div>
            <div class="step">
                <div class="step-num">5</div>
                <div class="step-text">
                    <strong>Wildcard search:</strong> Type <code style="color:#a78bfa">%</code> in the safe version — notice it searches literally for "%" rather than treating it as a wildcard. Parameterized queries also prevent wildcard abuse.
                </div>
            </div>
        </div>
    </div>

    <div class="footer">
        Built for educational purposes only • Always use parameterized queries in production • Never test on systems you don't own
    </div>

<script>
    // =========================================================
    //  SIMULATED IN-MEMORY DATABASE
    // =========================================================
    const DATABASE = {
        products: [
            { id: 1,  name: "Laptop Pro 15",      category: "Electronics", price: 1299.99, stock: 42  },
            { id: 2,  name: "Wireless Mouse",      category: "Electronics", price: 29.99,  stock: 150 },
            { id: 3,  name: "Mechanical Keyboard", category: "Electronics", price: 89.99,  stock: 75  },
            { id: 4,  name: "USB-C Hub",           category: "Electronics", price: 49.99,  stock: 200 },
            { id: 5,  name: "Monitor 27\"",        category: "Electronics", price: 399.99, stock: 30  },
            { id: 6,  name: "Laptop Stand",        category: "Accessories", price: 39.99,  stock: 90  },
            { id: 7,  name: "Webcam HD",           category: "Electronics", price: 79.99,  stock: 60  },
            { id: 8,  name: "Desk Lamp",           category: "Accessories", price: 24.99,  stock: 120 },
            { id: 9,  name: "Headphones Pro",      category: "Audio",       price: 199.99, stock: 45  },
            { id: 10, name: "Microphone USB",      category: "Audio",       price: 129.99, stock: 35  },
        ],
        // This table should NEVER be accessible from a product search!
        users: [
            { id: 1, username: "admin",       password: "hunter2",        role: "administrator" },
            { id: 2, username: "john.doe",    password: "password123",    role: "user"          },
            { id: 3, username: "jane.smith",  password: "qwerty456",      role: "moderator"     },
            { id: 4, username: "bob.wilson",  password: "letmein789",     role: "user"          },
        ]
    };

    // =========================================================
    //  ATTACK PRESETS
    // =========================================================
    const ATTACK_PRESETS = [
        {
            label: "Normal Search",
            payload: "laptop",
            description: "Normal search"
        },
        {
            label: "Always True",
            payload: "' OR '1'='1",
            description: "Returns all rows"
        },
        {
            label: "Always True (double quote)",
            payload: '" OR "1"="1',
            description: "Returns all rows"
        },
        {
            label: "UNION Attack",
            payload: "x' UNION SELECT id,username,password,role,role FROM users --",
            description: "Exposes users table"
        },
        {
            label: "Comment Bypass",
            payload: "anything' --",
            description: "Truncates query"
        },
        {
            label: "Wildcard Dump",
            payload: "' OR name LIKE '%",
            description: "Wildcard match all"
        },
        {
            label: "Empty String",
            payload: "",
            description: "Empty input"
        },
        {
            label: "Literal %",
            payload: "%",
            description: "Wildcard as literal"
        },
    ];

    // =========================================================
    //  VULNERABLE QUERY ENGINE (simulates string concatenation)
    // =========================================================
    function runVulnerableQuery(userInput) {
        // This simulates: "SELECT * FROM products WHERE name = '" + userInput + "'"
        // We parse the "injected" query to simulate what a real DB would do

        const constructedQuery = `SELECT * FROM products WHERE name = '${userInput}'`;

        let results = [];
        let isInjected = false;
        let injectionType = null;
        let exposedTable = null;

        const inputLower = userInput.toLowerCase();

        // Detect and simulate UNION attack
        if (inputLower.includes('union') && inputLower.includes('select')) {
            isInjected = true;
            injectionType = 'UNION';

            // Check if targeting users table
            if (inputLower.includes('users')) {
                exposedTable = 'users';
                // Simulate UNION result — mix products + users data
                const baseResults = getBaseProductResults(userInput);
                const unionResults = DATABASE.users.map(u => ({
                    id: u.id,
                    name: u.username,
                    category: u.password,   // password leaked into "category" column!
                    price: u.role,
                    stock: '⚠ LEAKED',
                    _isSecret: true
                }));
                results = [...baseResults, ...unionResults];
            } else {
                results = DATABASE.products;
            }
        }
        // Detect OR '1'='1' style bypass (always-true condition)
        else if (
            inputLower.includes("or '1'='1") ||
            inputLower.includes('or "1"="1') ||
            inputLower.includes('or 1=1') ||
            (inputLower.includes(' or ') && inputLower.includes("'"))
        ) {
            isInjected = true;
            injectionType = 'BYPASS';
            results = [...DATABASE.products]; // Return everything
        }
        // Detect LIKE wildcard injection
        else if (inputLower.includes("like '%") || inputLower.includes("like \"%")) {
            isInjected = true;
            injectionType = 'WILDCARD';
            results = [...DATABASE.products];
        }
        // Detect comment-based injection (--)
        else if (inputLower.includes('--') || inputLower.includes('/*')) {
            isInjected = true;
            injectionType = 'COMMENT';
            // Everything before the comment — simulate partial query
            const beforeComment = userInput.split('--')[0].split('/*')[0].trim();
            const cleanedInput = beforeComment.replace(/'/g, '').trim();
            results = DATABASE.products.filter(p =>
                p.name.toLowerCase().includes(cleanedInput.toLowerCase())
            );
        }
        // Normal (non-injected) case
        else {
            results = DATABASE.products.filter(p =>
                p.name.toLowerCase() === userInput.toLowerCase()
                || p.name.toLowerCase().includes(userInput.toLowerCase())
            );
        }

        return {
            constructedQuery,
            results,
            isInjected,
            injectionType,
            exposedTable,
            userInput
        };
    }

    function getBaseProductResults(userInput) {
        // Get the part before UNION
        const beforeUnion = userInput.toLowerCase().split('union')[0];
        const cleanInput = beforeUnion.replace(/'/g, '').trim();
        if (!cleanInput) return [];
        return DATABASE.products.filter(p =>
            p.name.toLowerCase().includes(cleanInput.toLowerCase())
        );
    }

    // =========================================================
    //  SAFE QUERY ENGINE (simulates parameterized query)
    // =========================================================
    function runSafeQuery(userInput) {
        // Simulates: db.execute("SELECT * FROM products WHERE name LIKE ?", ['%' + userInput + '%'])
        // The input is ALWAYS treated as a literal string — never as query logic

        const parameterizedQuery = `SELECT * FROM products WHERE name LIKE ?`;
        const boundParam = `%${userInput}%`;

        // Simple literal string match — injection attempts are just treated as plain text
        const results = DATABASE.products.filter(p =>
            p.name.toLowerCase().includes(userInput.toLowerCase())
        );

        return {
            parameterizedQuery,
            boundParam,
            results,
            userInput
        };
    }

    // =========================================================
    //  RENDER HELPERS
    // =========================================================
    function renderProductTable(results, isVulnerable) {
        if (!results || results.length === 0) {
            return `<div class="no-results">
                        <span class="icon">🔍</span>
                        No products found matching your search.
                    </div>`;
        }

        const rows = results.map(p => {
            const rowClass = p._isSecret ? 'secret-row' : '';
            const priceDisplay = typeof p.price === 'number'
                ? `$${p.price.toFixed(2)}`
                : `<span style="color:#fbbf24">${p.price}</span>`;
            const stockDisplay = p._isSecret
                ? `<span style="color:#ef4444">${p.stock}</span>`
                : p.stock;

            return `<tr class="${rowClass}">
                <td>${p.id}</td>
                <td>${escapeHtml(String(p.name))}</td>
                <td>${escapeHtml(String(p.category))}</td>
                <td class="price-cell">${priceDisplay}</td>
                <td>${stockDisplay}</td>
            </tr>`;
        }).join('');

        const headerStyle = isVulnerable ? 'color:#fca5a5' : 'color:#86efac';

        return `<table class="product-table">
            <thead>
                <tr>
                    <th style="${headerStyle}">ID</th>
                    <th style="${headerStyle}">Name</th>
                    <th style="${headerStyle}">Category</th>
                    <th style="${headerStyle}">Price</th>
                    <th style="${headerStyle}">Stock</th>
                </tr>
            </thead>
            <tbody>${rows}</tbody>
        </table>`;
    }

    function escapeHtml(str) {
        return str
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;');
    }

    function highlightInjection(query, userInput) {
        if (!userInput) return escapeHtml(query);
        const escaped = escapeHtml(query);
        const escapedInput = escapeHtml(userInput);
        if (escapedInput && escaped.includes(escapedInput)) {
            return escaped.replace(
                escapedInput,
                `<span class="injection-highlight">${escapedInput}</span>`
            );
        }
        return escaped;
    }

    // =========================================================
    //  MAIN RUN FUNCTION
    // =========================================================
    function runBothSearches() {
        const vulnInput = document.getElementById('vulnerableInput').value;
        const safeInput = document.getElementById('safeInput').value;

        // --- Vulnerable Side ---
        const vulnResult = runVulnerableQuery(vulnInput);

        document.getElementById('vulnerableQueryDisplay').innerHTML =
            highlightInjection(vulnResult.constructedQuery, vulnInput);

        const vulnStatusEl = document.getElementById('vulnerableStatus');
        if (vulnResult.isInjected) {
            let msg = '💀 INJECTION DETECTED! ';
            if (vulnResult.injectionType === 'UNION')
                msg += `UNION attack — ${vulnResult.exposedTable || 'unknown'} table exposed!`;
            else if (vulnResult.injectionType === 'BYPASS')
                msg += 'Always-true condition — ALL rows returned!';
            else if (vulnResult.injectionType === 'WILDCARD')
                msg += 'Wildcard injection — ALL rows matched!';
            else if (vulnResult.injectionType === 'COMMENT')
                msg += 'Comment injection — query truncated!';
            vulnStatusEl.className = 'status-bar status-injected';
            vulnStatusEl.textContent = msg;
        } else if (vulnInput === '') {
            vulnStatusEl.className = 'status-bar status-normal';
            vulnStatusEl.textContent = 'ℹ️ Enter a search term above';
        } else {
            vulnStatusEl.className = 'status-bar status-normal';
            vulnStatusEl.textContent = `✅ Normal query — ${vulnResult.results.length} result(s) found`;
        }

        const vulnCountEl = document.getElementById('vulnerableCount');
        vulnCountEl.innerHTML = vulnResult.results.length > 0
            ? `Showing <span>${vulnResult.results.length}</span> row(s)${vulnResult._isSecret ? ' ⚠️ includes leaked data!' : ''}`
            : '';

        document.getElementById('vulnerableResults').innerHTML =
            renderProductTable(vulnResult.results, true);

        // --- Safe Side ---
        const safeResult = runSafeQuery(safeInput);

        document.getElementById('safeQueryDisplay').innerHTML =
            `<span style="color:#86efac">${escapeHtml(safeResult.parameterizedQuery)}</span>` +
            `<br><span style="color:#6b7280; font-size:0.8rem">Bound parameter: </span>` +
            `<span style="color:#fbbf24">"${escapeHtml(safeResult.boundParam)}"</span>` +
            `<br><span style="color:#6b7280; font-size:0.75rem; font-style:italic">↑ Input treated as literal data, never as query logic</span>`;

        const safeStatusEl = document.getElementById('safeStatus');
        if (safeInput === '') {
            safeStatusEl.className = 'status-bar status-normal';
            safeStatusEl.textContent = 'ℹ️ Enter a search term above';
        } else {
            safeStatusEl.className = 'status-bar status-blocked';
            safeStatusEl.textContent = `🛡️ Input safely treated as data — ${safeResult.results.length} result(s) found`;
        }

        const safeCountEl = document.getElementById('safeCount');
        safeCountEl.innerHTML = safeResult.results.length > 0
            ? `Showing <span>${safeResult.results.length}</span> row(s)`
            : '';

        document.getElementById('safeResults').innerHTML =
            renderProductTable(safeResult.results, false);
    }

    // =========================================================
    //  DATABASE VIEWER
    // =========================================================
    let currentDbTable = 'products';

    function showTable(tableName) {
        currentDbTable = tableName;
        document.querySelectorAll('.db-tab').forEach(t => t.classList.remove('active'));
        event.target.classList.add('active');
        renderDbTable(tableName);
    }

    function renderDbTable(tableName) {
        const data = DATABASE[tableName];
        if (!data || data.length === 0) return;

        const keys = Object.keys(data[0]);
        const isSensitive = tableName === 'users';

        const headerCells = keys.map(k =>
            `<th style="${isSensitive ? 'color:#fbbf24' : 'color:#a78bfa'}">${k}</th>`
        ).join('');

        const rows = data.map(row => {
            const cells = keys.map(k => {
                let val = escapeHtml(String(row[k]));
                if (isSensitive && k === 'password') {
                    val = `<span style="color:#ef4444; font-weight:600">${val}</span>`;
                }
                return `<td>${val}</td>`;
            }).join('');
            return `<tr>${cells}</tr>`;
        }).join('');

        const note = isSensitive
            ? `<p style="color:#fbbf24; font-size:0.8rem; margin-top:8px">⚠️ This table should NEVER be accessible from a product search — but UNION injection can expose it!</p>`
            : '';

        document.getElementById('dbTableDisplay').innerHTML = `
            <table class="product-table">
                <thead><tr>${headerCells}</tr></thead>
                <tbody>${rows}</tbody>
            </table>
            ${note}
        `;
    }

    // =========================================================
    //  BUILD ATTACK PRESET BUTTONS
    // =========================================================
    function buildAttackButtons() {
        const container = document.getElementById('attackButtons');
        ATTACK_PRESETS.forEach(preset => {
            const btn = document.createElement('button');
            btn.className = 'attack-btn';
            btn.innerHTML = `<span class="attack-label">${preset.description}</span>${escapeHtml(preset.payload) || '(empty)'}`;
            btn.onclick = () => {
                document.getElementById('vulnerableInput').value = preset.payload;
                document.getElementById('safeInput').value = preset.payload;
                runBothSearches();
            };
            container.appendChild(btn);
        });
    }

