  + <span class="str">"%'"</span>;

<span class="cmt">// Final query becomes:</span>
<span class="cmt">// SELECT * FROM products</span>
<span class="cmt">// WHERE name LIKE '%' OR '1'='1%'</span>
<span class="cmt">// ↑ condition is always TRUE → dumps all rows</span>
                </div>
            </div>

            <div class="exp-block good">
                <h4>✅ Safe: Parameterized Query</h4>
