<span class="cmt">// User types: ' OR '1'='1</span>
<span class="kw">const</span> input = <span class="str">"' OR '1'='1"</span>;

<span class="cmt">// Query structure is fixed, input is a parameter</span>
<span class="kw">const</span> query = <span class="str">"SELECT * FROM products "</span>
  + <span class="str">"WHERE name LIKE ?"</span>;  <span class="cmt">// ← placeholder</span>

<span class="kw">const</span> params = [<span class="str">`%<span class="good-code">${input}</span>%`</span>];

<span class="cmt">// DB treats the entire input as a literal string</span>
<span class="cmt">// It searches for a product literally named:</span>
<span class="cmt">// "' OR '1'='1"  → no results, no breach</span>
