<script>
    // ─── In-Memory Database ───────────────────────────────────────────────────

    const database = [
        { id: 1,  name: "Laptop Pro 15",       category: "electronics", price: 1299.99, visible: true  },
        { id: 2,  name: "Wireless Headphones",  category: "electronics", price: 79.99,  visible: true  },
        { id: 3,  name: "USB-C Hub",            category: "electronics", price: 39.99,  visible: true  },
        { id: 4,  name: "Running Shoes",        category: "clothing",    price: 89.99,  visible: true  },
        { id: 5,  name: "Denim Jacket",         category: "clothing",    price: 59.99,  visible: true  },
        { id: 6,  name: "Organic Coffee",       category: "food",        price: 14.99,  visible: true  },
        { id: 7,  name: "Dark Chocolate Box",   category: "food",        price: 9.99,   visible: true  },
        { id: 8,  name: "JavaScript Deep Dive", category: "books",       price: 34.99,  visible: true  },
        { id: 9,  name: "Security Handbook",    category: "books",       price: 44.99,  visible: true  },
        { id: 10, name: "Admin Password List",  category: "secret",      price: 0.00,   visible: false },
        { id: 11, name: "Internal User Data",   category: "secret",      price: 0.00,   visible: false },
        { id: 12, name: "Credit Card Numbers",  category: "secret",      price: 0.00,   visible: false },
    ];

    // ─── Injection Hints ──────────────────────────────────────────────────────

    const injectionHints = [
        { code: "laptop",              desc: "Normal search — try this first" },
        { code: "' OR '1'='1",        desc: "Classic bypass — returns all rows" },
        { code: "' OR 1=1 --",        desc: "Comment-out the rest of the query" },
        { code: "' OR 'x'='x",        desc: "Always-true string comparison" },
        { code: "'; DROP TABLE --",    desc: "Destructive command attempt" },
        { code: "' OR category='secret", desc: "Target hidden category directly" },
        { code: "' UNION SELECT * --", desc: "UNION-based data extraction" },
        { code: "coffee",              desc: "Normal search — no injection" },
        { code: "' OR price=0 --",     desc: "Find free/hidden items" },
        { code: "xyz",                 desc: "No match — empty results" },
    ];

    // ─── Render DB Table ──────────────────────────────────────────────────────

    function renderDBTable() {
        const tbody = document.getElementById('dbTableBody');
        tbody.innerHTML = database.map(p => `
            <tr>
                <td>${p.id}</td>
                <td>${p.name}</td>
                <td><span class="tag tag-${p.category}">${p.category}</span></td>
                <td style="color:#ffd700">${p.price === 0 ? 'HIDDEN' : '$' + p.price.toFixed(2)}</td>
                <td>${p.visible
                    ? '<span style="color:#69ff9e">✓ public</span>'
                    : '<span style="color:#ff6b6b">✗ hidden</span>'}</td>
            </tr>
        `).join('');
    }

    // ─── Render Hints ─────────────────────────────────────────────────────────

    function renderHints() {
        const grid = document.getElementById('hintGrid');
        grid.innerHTML = injectionHints.map(h => `
            <div class="hint-chip" onclick="applyHint(${JSON.stringify(h.code)})">
                <span class="hint-code">${escapeHtml(h.code)}</span>
                <span class="hint-desc">${h.desc}</span>
            </div>
        `).join('');
    }

    function applyHint(code) {
        document.getElementById('vulnInput').value = code;
        document.getElementById('safeInput').value = code;
        runVulnerableSearch();
        runSafeSearch();
    }

    // ─── Vulnerable Search ────────────────────────────────────────────────────

    function runVulnerableSearch() {
        const raw = document.getElementById('vulnInput').value;

        // Simulate building a query via string concatenation
        const simulatedQuery = `SELECT * FROM products WHERE visible = true AND name LIKE '%${raw}%'`;

        // Display the constructed query with highlighting
        document.getElementById('vulnQuery').innerHTML = highlightVulnQuery(simulatedQuery, raw);

        // Simulate what a real SQL injection would do by parsing the input
        const results = simulateVulnerableFilter(raw);
        const { isInjection, injectionType } = detectInjection(raw);

        // Show alert
        const alertEl = document.getElementById('vulnAlert');
        if (isInjection) {
            alertEl.innerHTML = `<div class="alert alert-danger">
                ⚠️ <strong>Injection detected!</strong> ${injectionType} —
                query logic was manipulated. ${results.length} row(s) exposed.
            </div>`;
        } else {
            alertEl.innerHTML = `<div class="alert alert-info">
                ℹ️ Normal search executed. ${results.length} result(s) found.
            </div>`;
        }

        renderResults('vulnResults', results);
    }

    // ─── Safe Search ──────────────────────────────────────────────────────────

    function runSafeSearch() {
        const raw = document.getElementById('safeInput').value;

        // Simulate parameterized query — structure is fixed, input is just data
        const simulatedQuery = `SELECT * FROM products WHERE visible = true AND name LIKE ?`;
        const paramValue = `%${raw}%`;

        document.getElementById('safeQuery').innerHTML =
            `<span class="keyword">SELECT</span> * <span class="keyword">FROM</span> products ` +
            `<span class="keyword">WHERE</span> visible = <span class="param">true</span> ` +
            `<span class="keyword">AND</span> name <span class="keyword">LIKE</span> ` +
            `<span class="param">?</span>  ` +
            `<span style="color:#555">← param: </span><span class="param">"${escapeHtml(paramValue)}"</span>`;

        // Safe filter: always treats input as literal string, always requires visible=true
        const results = database.filter(p =>
            p.visible === true &&
            p.name.toLowerCase().includes(raw.toLowerCase())
        );

        const { isInjection } = detectInjection(raw);

        const alertEl = document.getElementById('safeAlert');
        if (isInjection) {
            alertEl.innerHTML = `<div class="alert alert-success">
                ✅ <strong>Injection attempt blocked!</strong> Input treated as literal text.
                ${results.length} result(s) found for the literal string.
            </div>`;
        } else {
            alertEl.innerHTML = `<div class="alert alert-success">
                ✅ Safe query executed. ${results.length} result(s) found.
            </div>`;
        }

        renderResults('safeResults', results);
    }

    // ─── Vulnerable Filter Simulation ─────────────────────────────────────────
    // This simulates what a real SQL engine would do when injection succeeds.
    // We parse the input for known injection patterns and apply their logic.

    function simulateVulnerableFilter(input) {
        const lower = input.toLowerCase().trim();

        // Pattern: ' OR '1'='1  or  ' OR 1=1  or  ' OR 'x'='x  → always true
        if (/'\s*or\s*'?1'?\s*=\s*'?1'?/i.test(input) ||
            /'\s*or\s*1\s*=\s*1/i.test(input) ||
            /'\s*or\s*'[^']+'\s*=\s*'[^']+'/i.test(input)) {
            // Returns ALL rows (injection bypassed the visible filter)
            return database;
        }

        // Pattern: ' OR category='secret'
        if (/'\s*or\s*category\s*=\s*'secret'/i.test(input)) {
            return database.filter(p => p.category === 'secret');
        }

        // Pattern: ' OR price=0
        if (/'\s*or\s*price\s*=\s*0/i.test(input)) {
            return database.filter(p => p.price === 0);
        }

        // Pattern: UNION SELECT or DROP TABLE or comment-based
        if (/union\s+select/i.test(input) ||
            /drop\s+table/i.test(input) ||
            /--/.test(input)) {
            // Simulate a "dump all" or destructive result
            return database;
        }

        // Normal case: filter visible products by name
        return database.filter(p =>
            p.visible === true &&
            p.name.toLowerCase().includes(lower)
        );
    }

    // ─── Injection Detection ──────────────────────────────────────────────────

    function detectInjection(input) {
        const patterns = [
            { re: /'\s*or\s*/i,           type: "OR-based bypass" },
            { re: /'\s*and\s*/i,          type: "AND-based manipulation" },
            { re: /--/,                   type: "Comment injection (--)" },
            { re: /;\s*(drop|delete|truncate|insert|update)/i, type: "Stacked query / destructive command" },
            { re: /union\s+select/i,      type: "UNION-based extraction" },
            { re: /'\s*=\s*'/,            type: "Always-true string comparison" },
        ];
        for (const p of patterns) {
            if (p.re.test(input)) return { isInjection: true, injectionType: p.type };
        }
        return { isInjection: false, injectionType: null };
    }

    // ─── Render Results ───────────────────────────────────────────────────────

    function renderResults(containerId, results) {
        const el = document.getElementById(containerId);
        if (results.length === 0) {
            el.innerHTML = `<div class="no-results">No products found.</div>`;
            return;
        }
        el.innerHTML = results.map(p => `
            <div class="product-card" style="${!p.visible ? 'border-color:#ff4444;background:rgba(255,68,68,0.05)' : ''}">
                <div>
                    <div class="product-name">
                        ${!p.visible ? '🔴 ' : ''}${escapeHtml(p.name)}
                        ${!p.visible ? '<span style="color:#ff6b6b;font-size:0.72rem;margin-left:6px">[HIDDEN ROW EXPOSED]</span>' : ''}
                    </div>
                    <div class="product-meta">
                        <span class="tag tag-${p.category}">${p.category}</span>
                        &nbsp; ID: ${p.id}
                    </div>
                </div>
                <div class="product-price">${p.price === 0 ? '⚠️ $0.00' : '$' + p.price.toFixed(2)}</div>
            </div>
        `).join('');
    }

    // ─── Query Highlighting ───────────────────────────────────────────────────

    function highlightVulnQuery(query, userInput) {
        // Escape the full query for display, then highlight the injected part
        const escapedQuery = escapeHtml(query);
        const escapedInput = escapeHtml(userInput);

        const { isInjection } = detectInjection(userInput);
        const spanClass = isInjection ? 'injected' : 'value';

        return escapedQuery.replace(
            escapedInput,
            `<span class="${spanClass}">${escapedInput}</span>`
        ).replace(/\b(SELECT|FROM|WHERE|AND|OR|LIKE|DROP|UNION|INSERT|UPDATE|DELETE|TABLE)\b/g,
            '<span class="keyword">$1</span>'
        );
    }

    // ─── Utility ──────────────────────────────────────────────────────────────

    function escapeHtml(str) {
        return String(str)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#39;');
    }

    // ─── Init ─────────────────────────────────────────────────────────────────

    renderDBTable();
    renderHints();
    runVulnerableSearch();
    runSafeSearch();

    // Sync inputs so both panels update together when typing
    document.getElementById('vulnInput').addEventListener('keydown', e => {
        if (e.key === 'Enter') { runVulnerableSearch(); runSafeSearch(); }
    });
    document.getElementById('safeInput').addEventListener('keydown', e => {
        if (e.key === 'Enter') { runVulnerableSearch(); runSafeSearch(); }
    });
</script>
</body>
</html>
