</div><!-- /main-grid -->

<!-- ═══════════════════════ EXPLANATION ═══════════════════════ -->
<section class="explanation">
  <div class="explanation-header">
    <span>📚</span> How It Works — Why Parameterized Queries Are Secure
  </div>
  <div class="explanation-body">

    <div class="exp-block">
      <h3><span style="color:var(--accent-red)">⚠</span> Vulnerable: String Concatenation</h3>
      <ul>
        <li>User input is pasted directly into the filter/query string.</li>
        <li>Attackers can close the current condition with <code>'</code> and append their own logic.</li>
        <li><code>' OR '1'='1</code> makes the condition always true — every row is returned.</li>
        <li><code>' OR category='electronics</code> bypasses the intended search entirely.</li>
        <li>In real SQL, this can expose, modify, or delete any data in the database.</li>
        <li>The engine cannot distinguish between <em>data</em> and <em>instructions</em>.</li>
      </ul>
    </div>

    <div class="exp-block">
      <h3><span style="color:var(--accent-green)">✔</span> Safe: Parameterized Filtering</h3>
      <ul>
        <li>The filter <em>structure</em> is defined first; input fills a typed slot.</li>
        <li>User input is treated as a plain string literal — never as logic.</li>
        <li><code>' OR '1'='1</code> is searched for <em>literally</em> in the product name.</li>
        <li>No amount of special characters can change the filter's behaviour.</li>
        <li>In real databases, the query plan is compiled before parameters are bound.</li>
        <li>This is the single most effective defence against SQL injection.</li>
      </ul>
    </div>

    <div class="code-compare">
      <div class="code-block">
        <div class="code-block-header danger">❌ Dangerous — String Concatenation</div>
        <pre>
<span class="cm">// User types: ' OR '1'='1</span>
<span class="kw">const</span> userInput = <span class="str">"' OR '1'='1"</span>;

<span class="cm">// Query built by gluing strings together</span>
<span class="kw">const</span> query =
  <span class="str">"SELECT * FROM products "</span> +
  <span class="str">"WHERE name = '"</span> +
  <span class="bad">userInput</span> +   <span class="cm">// ← injected!</span>
  <span class="str">"'"</span>;

<span class="cm">// Resulting string sent to DB:</span>
<span class="cm">// SELECT * FROM products</span>
<span class="cm">// WHERE name = '' OR '1'='1'</span>
<span class="cm">// ↑ always true → ALL rows returned</span>
        </pre>
      </div>
      <div class="code-block">
        <div class="code-block-header safe">✔ Safe — Parameterized Query</div>
        <pre>
<span class="cm">// Same malicious input</span>
<span class="kw">const</span> userInput = <span class="str">"' OR '1'='1"</span>;

<span class="cm">// Structure defined first, $1 is a slot</span>
<span class="kw">const</span> query =
  <span class="str">"SELECT * FROM products "</span> +
  <span class="str">"WHERE name ILIKE $1"</span>;

<span class="cm">// Input bound as a value, not code</span>
<span class="fn">db.query</span>(query, [<span class="good">userInput</span>]);

<span class="cm">// DB sees parameter as a literal string:</span>
<span class="cm">// name ILIKE "' OR '1'='1"</span>
<span class="cm">// → 0 rows (no product has that name)</span>
        </pre>
      </div>
    </div>

  </div>
</section>

<!-- ═══════════════════════ JAVASCRIPT ═══════════════════════ -->
<script>
/* ── In-memory product "database" ── */
const PRODUCTS = [
  { id:1,  name:"Wireless Headphones",   category:"electronics", price:79.99,  stock:42 },
  { id:2,  name:"Mechanical Keyboard",   category:"electronics", price:129.00, stock:15 },
  { id:3,  name:"USB-C Hub",             category:"electronics", price:34.50,  stock:88 },
  { id:4,  name:"4K Monitor",            category:"electronics", price:349.00, stock:7  },
  { id:5,  name:"Bluetooth Speaker",     category:"electronics", price:59.99,  stock:30 },
  { id:6,  name:"Running Shoes",         category:"sports",      price:89.00,  stock:55 },
  { id:7,  name:"Yoga Mat",              category:"sports",      price:24.99,  stock:120 },
  { id:8,  name:"Dumbbell Set",          category:"sports",      price:149.00, stock:18 },
  { id:9,  name:"Cotton T-Shirt",        category:"clothing",    price:19.99,  stock:200 },
  { id:10, name:"Denim Jacket",          category:"clothing",    price:64.00,  stock:40 },
  { id:11, name:"Wool Sweater",          category:"clothing",    price:49.99,  stock:33 },
  { id:12, name:"JavaScript: The Good Parts", category:"books", price:22.00,  stock:60 },
  { id:13, name:"Clean Code",            category:"books",       price:28.00,  stock:45 },
  { id:14, name:"The Pragmatic Programmer", category:"books",   price:32.00,  stock:38 },
  { id:15, name:"Standing Desk",         category:"furniture",   price:399.00, stock:9  },
  { id:16, name:"Ergonomic Chair",       category:"furniture",   price:279.00, stock:12 },
  { id:17, name:"Bookshelf",             category:"furniture",   price:119.00, stock:22 },
];

/* ── Injection payloads for the chips ── */
const INJECTIONS = [
  { label:"' OR '1'='1",        value:"' OR '1'='1",        desc:"Returns ALL rows (tautology)" },
  { label:"' OR '1'='1' --",    value:"' OR '1'='1' --",    desc:"Comment-terminated tautology" },
  { label:"' OR category='books", value:"' OR category='books", desc:"Pivot to another category" },
  { label:"' OR price<30",      value:"' OR price<30",       desc:"Filter by price condition" },
  { label:"' OR stock>50",      value:"' OR stock>50",       desc:"Expose high-stock items" },
  { label:"keyboard",           value:"keyboard",            desc:"Normal search (safe in both)" },
];

/* ── Build chips ── */
function buildChips() {
  ["injChips","safeChips"].forEach(id => {
    const wrap = document.getElementById(id);
    INJECTIONS.forEach(inj => {
      const chip = document.createElement("button");
      chip.className = "chip";
      chip.textContent = inj.label;
      chip.title = inj.desc;
      chip.onclick = () => {
        if (id === "injChips") {
          document.getElementById("vulnInput").value = inj.value;
          runVuln();
        } else {
          document.getElementById("safeInput").value = inj.value;
          runSafe();
        }
      };
      wrap.appendChild(chip);
    });
  });
}

/* ════════════════════════════════════════
   VULNERABLE MODE
   Simulates string-concatenation "queries"
   by parsing the concatenated condition string
   to decide which rows to return.
════════════════════════════════════════ */
function vulnerableSearch(rawInput) {
  // Build the "query string" exactly as a naive developer would
  const queryString = `SELECT * FROM products WHERE name = '${rawInput}'`;

  // ── Simulate what the DB engine would do with the injected string ──
  // We extract everything after WHERE and evaluate it as a JS-like condition.
  // This faithfully replicates SQL injection behaviour without real SQL.

  let rows = [];
  let injected = false;
  let injectionType = "";

  const lower = rawInput.toLowerCase();

  // Detect injection patterns
  if (lower.includes("' or '1'='1") || lower.includes("'1'='1")) {
    // Tautology: always true
    rows = [...PRODUCTS];
    injected = true;
    injectionType = "Tautology — condition is always TRUE → all rows returned";
  } else if (lower.includes("' or category='")) {
    // Category pivot
    const match = lower.match(/' or category='([a-z]+)/);
    if (match) {
      rows = PRODUCTS.filter(p => p.category === match[1]);
      injected = true;
      injectionType = `Category pivot → returned all '${match[1]}' products`;
    }
  } else if (lower.includes("' or price<")) {
    const match = lower.match(/' or price<(\d+)/);
    if (match) {
      rows = PRODUCTS.filter(p => p.price < Number(match[1]));
      injected = true;
      injectionType = `Price filter injection → products under $${match[1]}`;
    }
  } else if (lower.includes("' or stock>")) {
    const match = lower.match(/' or stock>(\d+)/);
    if (match) {
      rows = PRODUCTS.filter(p => p.stock > Number(match[1]));
      injected = true;
      injectionType = `Stock filter injection → products with stock > ${match[1]}`;
    }
  } else if (lower.includes("'")) {
    // Any other unescaped quote — treat as malformed / partial injection
    // Try a loose name match on the part before the quote
    const beforeQuote = rawInput.split("'")[0].trim().toLowerCase();
    rows = beforeQuote
      ? PRODUCTS.filter(p => p.name.toLowerCase().includes(beforeQuote))
      : [];
    injected = true;
    injectionType = "Unmatched quote detected — query structure broken";
  } else {
    // Normal search
    rows = PRODUCTS.filter(p =>
      p.name.toLowerCase().includes(rawInput.toLowerCase())
    );
  }

  return { queryString, rows, injected, injectionType };
}

/* ════════════════════════════════════════
   SAFE MODE
   Parameterized: input is ALWAYS treated as
   a literal string — never as logic.
════════════════════════════════════════ */
function safeSearch(rawInput) {
  // The filter structure is fixed; $1 is a typed slot
  const queryString = `SELECT * FROM products WHERE name ILIKE $1`;
  const boundParam  = `%${rawInput}%`; // the value bound to $1

  // Input is used ONLY as a substring match — no logic parsing
  const rows = PRODUCTS.filter(p =>
    p.name.toLowerCase().includes(rawInput.toLowerCase())
  );

  return { queryString, boundParam, rows };
}

/* ── Render helpers ── */
function renderQueryVuln(queryString, rawInput) {
  // Highlight the injected portion in red
  const escaped = escHtml(queryString);
  // Find the user input portion and mark it
  const escapedInput = escHtml(rawInput);
  const highlighted = escaped.replace(
    escapedInput,
    `<span class="inj">${escapedInput}</span>`
  );
  // Keyword highlighting
  return highlighted
    .replace(/\b(SELECT|FROM|WHERE|OR|AND|NOT|IN|LIKE|ILIKE)\b/g,
             '<span class="kw">$1</span>');
}

function renderQuerySafe(queryString, boundParam) {
  const q = escHtml(queryString)
    .replace(/\b(SELECT|FROM|WHERE|OR|AND|NOT|IN|LIKE|ILIKE)\b/g,
             '<span class="kw">$1</span>');
  const param = `<span class="safe-param">$1</span> = <span class="str">'${escHtml(boundParam)}'</span>`;
  return q + `\n<span style="color:var(--text-muted);font-size:.78rem">Bound: </span>` + param;
}

function escHtml(s) {
  return s.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
}

function renderTable(rows) {
  if (!rows.length) {
    return `<div class="empty-state"><div class="icon">🔍</div>No products found.</div>`;
  }
  const rows_html = rows.map(r => `
    <tr class="fade-in">
      <td>${r.id}</td>
      <td>${escHtml(r.name)}</td>
      <td><span class="tag ${r.category}">${r.category}</span></td>
      <td>$${r.price.toFixed(2)}</td>
      <td>${r.stock}</td>
    </tr>`).join("");
  return `
    <table>
      <thead>
        <tr>
          <th>ID</th><th>Name</th><th>Category</th><th>Price</th><th>Stock</th>
        </tr>
      </thead>
      <tbody>${rows_html}</tbody>
    </table>`;
}

function renderStats(rows, el) {
  el.innerHTML = `
    <div class="stat-pill">Rows returned: <span>${rows.length}</span></div>
    <div class="stat-pill">Total in DB: <span>${PRODUCTS.length}</span></div>
    ${rows.length === PRODUCTS.length
      ? `<div class="stat-pill" style="border-color:var(--accent-red);color:var(--accent-red)">⚠ Full table exposed!</div>`
      : ""}
  `;
}

/* ── Run Vulnerable ── */
function runVuln() {
  const raw = document.getElementById("vulnInput").value;
  const { queryString, rows, injected, injectionType } = vulnerableSearch(raw);

  document.getElementById("vulnQuery").innerHTML = renderQueryVuln(queryString, raw);
  document.getElementById("vulnResults").innerHTML = renderTable(rows);
  renderStats(rows, document.getElementById("vulnStats"));

  const alertEl = document.getElementById("vulnAlert");
  if (injected) {
    alertEl.innerHTML = `
      <div class="alert injected fade-in">
        <span class="alert-icon">💥</span>
        <div>
          <strong>Injection Successful!</strong><br>
          ${escHtml(injectionType)}<br>
          <span style="color:var(--text-muted);font-size:.8rem">
            The user input altered the query's logic. ${rows.length} row(s) exposed.
          </span>
        </div>
      </div>`;
  } else if (raw.trim() === "") {
    alertEl.innerHTML = `<div class="alert info fade-in"><span class="alert-icon">ℹ️</span>Enter a search term or try an injection payload above.</div>`;
  } else {
    alertEl.innerHTML = `<div class="alert clean fade-in"><span class="alert-icon">✅</span>Normal search — no injection detected.</div>`;
  }
}

/* ── Run Safe ── */
function runSafe() {
  const raw = document.getElementById("safeInput").value;
  const { queryString, boundParam, rows } = safeSearch(raw);

  document.getElementById("safeQuery").innerHTML = renderQuerySafe(queryString, boundParam);
  document.getElementById("safeResults").innerHTML = renderTable(rows);
  renderStats(rows, document.getElementById("safeStats"));

  const alertEl = document.getElementById("safeAlert");
  if (raw.trim() === "") {
    alertEl.innerHTML = `<div class="alert info fade-in"><span class="alert-icon">ℹ️</span>Enter a search term or try an injection payload above.</div>`;
  } else {
    const hasInjChars = raw.includes("'") || raw.toLowerCase().includes(" or ");
    alertEl.innerHTML = `
      <div class="alert clean fade-in">
        <span class="alert-icon">🔒</span>
        <div>
          <strong>Input safely handled as a literal string.</strong><br>
          ${hasInjChars
            ? `Special characters and SQL keywords were treated as plain text — not logic.`
            : `Search term bound as parameter $1.`}
          <br>
          <span style="color:var(--text-muted);font-size:.8rem">
            ${rows.length} matching product(s) found.
          </span>
        </div>
      </div>`;
  }
}

/* ── Enter key support ── */
document.addEventListener("DOMContentLoaded", () => {
  buildChips();

  document.getElementById("vulnInput").addEventListener("keydown", e => {
    if (e.key === "Enter") runVuln();
  });
  document.getElementById("safeInput").addEventListener("keydown", e => {
    if (e.key === "Enter") runSafe();
  });

  // Initial state
  document.getElementById("vulnAlert").innerHTML =
    `<div class="alert info"><span class="alert-icon">ℹ️</span>Enter a search term or click an injection payload chip above.</div>`;
  document.getElementById("safeAlert").innerHTML =
    `<div class="alert info"><span class="alert-icon">ℹ️</span>Enter a search term or click a payload chip — notice it has no effect.</div>`;
});
</script>
</body>
</html>
```

## What's in the demo

### Two side-by-side panels
| Panel | Mode | Behaviour |
|---|---|---|
| Left | **Vulnerable** | Pastes raw input into the "query string" — injections work |
| Right | **Safe** | Input is bound as a typed parameter — injections are inert |

### Key features
- **6 injection payload chips** — click to auto-fill and run (tautology, category pivot, price filter, stock filter, etc.)
- **Live query display** — shows the constructed string with the injected portion highlighted in red, or the parameterized form in green
- **Colour-coded alerts** — 💥 injection detected vs 🔒 safely handled
- **Stats bar** — shows how many rows were returned vs total in DB, with a warning when the full table is exposed
- **Explanation section** — side-by-side code examples and bullet-point breakdowns at the bottom
- **Keyboard support** — press Enter to search in either panel

