      --radius:    10px;
      --shadow:    0 4px 24px rgba(0,0,0,.45);
    }

    body {
      font-family: 'Segoe UI', system-ui, sans-serif;
      background: var(--bg);
      color: var(--text);
      min-height: 100vh;
      padding: 24px 16px 60px;
    }

    h1 {
      text-align: center;
      font-size: clamp(1.4rem, 3vw, 2rem);
      margin-bottom: 6px;
      background: linear-gradient(135deg, var(--accent), #a78bfa);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
    }

    .subtitle {
      text-align: center;
      color: var(--muted);
      font-size: .9rem;
      margin-bottom: 32px;
    }

    /* ── Layout ── */
    .wrapper { max-width: 1100px; margin: 0 auto; }

    .card {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: var(--radius);
      padding: 20px 24px;
      box-shadow: var(--shadow);
    }

    /* ── Search Bar ── */
    .search-section {
      display: flex;
      flex-wrap: wrap;
      gap: 10px;
      align-items: center;
      margin-bottom: 24px;
    }

    .search-section label {
      font-weight: 600;
      color: var(--muted);
      font-size: .85rem;
      text-transform: uppercase;
      letter-spacing: .06em;
      flex-shrink: 0;
    }

    #searchInput {
      flex: 1 1 260px;
      background: var(--code-bg);
      border: 1px solid var(--border);
      color: var(--text);
      padding: 10px 14px;
      border-radius: 8px;
      font-size: 1rem;
      font-family: 'Consolas', monospace;
      outline: none;
      transition: border-color .2s;
    }
    #searchInput:focus { border-color: var(--accent); }

    .btn {
      padding: 10px 20px;
      border-radius: 8px;
      border: none;
      cursor: pointer;
      font-size: .9rem;
      font-weight: 600;
      transition: opacity .2s, transform .1s;
    }
    .btn:active { transform: scale(.97); }
    .btn:hover  { opacity: .88; }

    .btn-primary { background: var(--accent);  color: #fff; }
    .btn-danger  { background: var(--danger);  color: #fff; }
    .btn-success { background: var(--success); color: #0f1117; }

    /* ── Payloads ── */
    .payloads-section { margin-bottom: 28px; }
    .payloads-section h3 {
      font-size: .8rem;
      text-transform: uppercase;
      letter-spacing: .08em;
      color: var(--muted);
      margin-bottom: 10px;
    }
    .payload-grid {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;
    }
    .payload-btn {
      background: var(--surface2);
      border: 1px solid var(--border);
      color: var(--text);
      padding: 6px 12px;
      border-radius: 6px;
      font-size: .8rem;
      font-family: 'Consolas', monospace;
      cursor: pointer;
      transition: background .15s, border-color .15s;
    }
    .payload-btn:hover {
      background: var(--border);
      border-color: var(--accent);
    }
    .payload-btn.attack { border-color: var(--danger); color: var(--danger); }
    .payload-btn.safe   { border-color: var(--success); color: var(--success); }

    /* ── Two-panel results ── */
    .panels {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 20px;
      margin-bottom: 28px;
    }
    @media (max-width: 720px) { .panels { grid-template-columns: 1fr; } }

    .panel { display: flex; flex-direction: column; gap: 12px; }

    .panel-header {
      display: flex;
      align-items: center;
      gap: 10px;
      padding: 12px 16px;
      border-radius: 8px;
      font-weight: 700;
      font-size: .95rem;
    }
    .panel-header.vuln  { background: rgba(247,95,95,.15);  border: 1px solid var(--danger);  color: var(--danger);  }
    .panel-header.safe  { background: rgba(79,207,142,.15); border: 1px solid var(--success); color: var(--success); }
    .panel-header .icon { font-size: 1.3rem; }

    /* ── Query display ── */
    .query-box {
      background: var(--code-bg);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 10px 14px;
      font-family: 'Consolas', monospace;
      font-size: .82rem;
      line-height: 1.6;
      word-break: break-all;
      min-height: 48px;
    }
    .query-box .kw   { color: #c792ea; font-weight: 700; }
    .query-box .str  { color: var(--warn); }
    .query-box .inj  { color: var(--danger); background: rgba(247,95,95,.18); border-radius: 3px; padding: 0 2px; }
    .query-box .param{ color: var(--success); }

    /* ── Alert banner ── */
    .alert-banner {
      display: none;
      align-items: center;
      gap: 10px;
      padding: 10px 14px;
      border-radius: 8px;
      font-size: .85rem;
      font-weight: 600;
    }
    .alert-banner.show { display: flex; }
    .alert-banner.danger  { background: rgba(247,95,95,.2);  border: 1px solid var(--danger);  color: var(--danger);  }
    .alert-banner.success { background: rgba(79,207,142,.2); border: 1px solid var(--success); color: var(--success); }

    /* ── Table ── */
    .table-wrap {
      border-radius: 8px;
      overflow: hidden;
      border: 1px solid var(--border);
    }
    table {
      width: 100%;
      border-collapse: collapse;
      font-size: .85rem;
    }
    thead th {
      background: var(--surface2);
      padding: 9px 12px;
      text-align: left;
      font-size: .75rem;
      text-transform: uppercase;
      letter-spacing: .06em;
      color: var(--muted);
      border-bottom: 1px solid var(--border);
    }
    tbody tr { border-bottom: 1px solid var(--border); transition: background .12s; }
    tbody tr:last-child { border-bottom: none; }
    tbody tr:hover { background: var(--surface2); }
    tbody td { padding: 9px 12px; }

    .badge {
      display: inline-block;
      padding: 2px 8px;
      border-radius: 20px;
      font-size: .72rem;
      font-weight: 700;
    }
    .badge-electronics { background: rgba(79,142,247,.2); color: var(--accent); }
    .badge-clothing    { background: rgba(167,139,250,.2); color: #a78bfa; }
    .badge-food        { background: rgba(79,207,142,.2); color: var(--success); }
    .badge-tools       { background: rgba(247,201,79,.2); color: var(--warn); }
    .badge-books       { background: rgba(247,95,95,.2);  color: var(--danger); }

    .empty-state {
      padding: 28px;
      text-align: center;
      color: var(--muted);
      font-size: .9rem;
    }

    .row-count {
      font-size: .78rem;
      color: var(--muted);
      text-align: right;
      padding: 4px 2px;
    }

    /* ── Explanation ── */
    .explanation { margin-top: 8px; }
    .explanation h2 {
      font-size: 1.1rem;
      margin-bottom: 16px;
      color: var(--text);
    }
    .exp-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 16px;
      margin-bottom: 20px;
    }
    @media (max-width: 620px) { .exp-grid { grid-template-columns: 1fr; } }

    .exp-card {
      background: var(--surface2);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 16px;
    }
    .exp-card h3 {
      font-size: .85rem;
      margin-bottom: 10px;
      display: flex;
      align-items: center;
      gap: 8px;
    }
    .exp-card p, .exp-card li {
      font-size: .82rem;
      color: var(--muted);
      line-height: 1.65;
    }
    .exp-card ul { padding-left: 18px; }
    .exp-card ul li { margin-bottom: 4px; }

    .code-block {
      background: var(--code-bg);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 14px 16px;
      font-family: 'Consolas', monospace;
      font-size: .8rem;
      line-height: 1.7;
      overflow-x: auto;
      margin-top: 16px;
    }
    .code-block .comment { color: var(--muted); }
    .code-block .kw      { color: #c792ea; }
    .code-block .fn      { color: var(--accent); }
    .code-block .str     { color: var(--warn); }
    .code-block .good    { color: var(--success); }
    .code-block .bad     { color: var(--danger); }

    /* ── How it works steps ── */
    .steps { display: flex; flex-direction: column; gap: 10px; margin-top: 16px; }
    .step {
      display: flex;
      gap: 12px;
      align-items: flex-start;
      background: var(--surface2);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 12px 14px;
    }
    .step-num {
      width: 26px; height: 26px;
      border-radius: 50%;
      display: flex; align-items: center; justify-content: center;
      font-weight: 700; font-size: .8rem;
      flex-shrink: 0;
    }
    .step-num.red   { background: rgba(247,95,95,.25);  color: var(--danger);  }
    .step-num.green { background: rgba(79,207,142,.25); color: var(--success); }
    .step p { font-size: .82rem; color: var(--muted); line-height: 1.6; margin: 0; }
    .step p strong { color: var(--text); }

    /* ── Divider ── */
    hr { border: none; border-top: 1px solid var(--border); margin: 24px 0; }

    /* ── Scrollbar ── */
    ::-webkit-scrollbar { width: 6px; height: 6px; }
    ::-webkit-scrollbar-track { background: var(--surface); }
    ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
  </style>
</head>
<body>
<div class="wrapper">

  <h1>🔓 SQL Injection Demo</h1>
  <p class="subtitle">Interactive playground — see how injection attacks work and why parameterized queries stop them</p>

  <!-- Search Card -->
  <div class="card" style="margin-bottom:20px">
    <div class="search-section">
      <label for="searchInput">Search Term</label>
      <input id="searchInput" type="text" placeholder="e.g.  laptop  or  ' OR '1'='1" value="laptop" spellcheck="false"/>
      <button class="btn btn-primary" onclick="runSearch()">🔍 Search</button>
      <button class="btn" style="background:var(--surface2);border:1px solid var(--border)" onclick="clearSearch()">✕ Clear</button>
    </div>

    <!-- Preset Payloads -->
    <div class="payloads-section">
      <h3>⚡ Quick Payloads — click to load</h3>
      <div class="payload-grid">
        <button class="payload-btn safe"   onclick="setPayload('laptop')">laptop</button>
        <button class="payload-btn safe"   onclick="setPayload('shirt')">shirt</button>
        <button class="payload-btn safe"   onclick="setPayload('coffee')">coffee</button>
        <button class="payload-btn safe"   onclick="setPayload('')">(empty)</button>
        <button class="payload-btn attack" onclick="setPayload(&quot;' OR '1'='1&quot;)">' OR '1'='1</button>
        <button class="payload-btn attack" onclick="setPayload(&quot;' OR 1=1--&quot;)">' OR 1=1--</button>
        <button class="payload-btn attack" onclick="setPayload(&quot;' OR 'a'='a&quot;)">' OR 'a'='a</button>
        <button class="payload-btn attack" onclick="setPayload(&quot;laptop' OR '1'='1&quot;)">laptop' OR '1'='1</button>
        <button class="payload-btn attack" onclick="setPayload(&quot;%' OR 1=1--&quot;)">%' OR 1=1--</button>
        <button class="payload-btn attack" onclick="setPayload(&quot;'; DROP TABLE products--&quot;)">'; DROP TABLE products--</button>
      </div>
    </div>
  </div>

  <!-- Results Panels -->
  <div class="panels">

    <!-- Vulnerable Panel -->
    <div class="panel" id="vulnPanel">
      <div class="panel-header vuln">
        <span class="icon">💀</span>
        <div>
          <div>Vulnerable Mode</div>
          <div style="font-size:.72rem;font-weight:400;opacity:.8">String concatenation — unsafe</div>
        </div>
      </div>

      <div>
        <div style="font-size:.72rem;color:var(--muted);margin-bottom:4px;text-transform:uppercase;letter-spacing:.06em">Constructed Query</div>
        <div class="query-box" id="vulnQuery">—</div>
      </div>

      <div class="alert-banner" id="vulnAlert"></div>

      <div class="table-wrap">
        <table>
          <thead>
            <tr>
              <th>ID</th><th>Name</th><th>Category</th><th>Price</th><th>Stock</th>
            </tr>
          </thead>
          <tbody id="vulnResults">
            <tr><td colspan="5" class="empty-state">Run a search to see results</td></tr>
          </tbody>
        </table>
      </div>
      <div class="row-count" id="vulnCount"></div>
    </div>

    <!-- Safe Panel -->
    <div class="panel" id="safePanel">
      <div class="panel-header safe">
        <span class="icon">🛡️</span>
        <div>
          <div>Safe Mode</div>
          <div style="font-size:.72rem;font-weight:400;opacity:.8">Parameterized filtering — secure</div>
        </div>
      </div>

      <div>
        <div style="font-size:.72rem;color:var(--muted);margin-bottom:4px;text-transform:uppercase;letter-spacing:.06em">Parameterized Query</div>
        <div class="query-box" id="safeQuery">—</div>
      </div>

      <div class="alert-banner" id="safeAlert"></div>

      <div class="table-wrap">
        <table>
          <thead>
            <tr>
              <th>ID</th><th>Name</th><th>Category</th><th>Price</th><th>Stock</th>
            </tr>
          </thead>
          <tbody id="safeResults">
            <tr><td colspan="5" class="empty-state">Run a search to see results</td></tr>
          </tbody>
        </table>
      </div>
      <div class="row-count" id="safeCount"></div>
    </div>

  </div>

  <!-- Explanation -->
  <div class="card explanation">
    <h2>📖 How SQL Injection Works — and How to Stop It</h2>

    <div class="exp-grid">
      <div class="exp-card">
        <h3><span style="color:var(--danger)">💀</span> Why String Concatenation Is Dangerous</h3>
        <p>When user input is directly embedded into a query string, the database cannot distinguish between <em>data</em> and <em>commands</em>. An attacker can craft input that closes the original string and appends new logic.</p>
        <ul style="margin-top:10px">
          <li>Input <code style="color:var(--warn)">' OR '1'='1</code> always evaluates to true</li>
          <li>Input <code style="color:var(--warn)">'; DROP TABLE--</code> can destroy data</li>
          <li>Input <code style="color:var(--warn)">UNION SELECT</code> can exfiltrate other tables</li>
          <li>The database executes whatever is injected</li>
        </ul>
      </div>

      <div class="exp-card">
        <h3><span style="color:var(--success)">🛡️</span> Why Parameterized Queries Are Safe</h3>
        <p>Parameterized queries (also called prepared statements) send the query <em>structure</em> and the <em>data</em> separately. The database driver handles escaping automatically.</p>
        <ul style="margin-top:10px">
          <li>The placeholder <code style="color:var(--success)">?</code> is never treated as SQL syntax</li>
          <li>Special characters like <code>'</code> are automatically escaped</li>
          <li>The query structure is fixed — data cannot change it</li>
          <li>Works regardless of what the user types</li>
        </ul>
      </div>
    </div>

    <hr/>

    <div class="code-block">
<span class="comment">// ❌ VULNERABLE — string concatenation</span>
<span class="kw">const</span> query = <span class="str">"SELECT * FROM products WHERE name LIKE '%"</span> + <span class="bad">userInput</span> + <span class="str">"%'"</span>;
<span class="comment">// If userInput = "' OR '1'='1"  →  WHERE name LIKE '%' OR '1'='1%'</span>
<span class="comment">// This returns ALL rows — the attacker bypassed the filter!</span>

<span class="comment">// ✅ SAFE — parameterized query (Node.js / mysql2 example)</span>
<span class="kw">const</span> query = <span class="str">"SELECT * FROM products WHERE name LIKE ?"</span>;
<span class="kw">const</span> params = [<span class="str">`%<span class="good">${userInput}</span>%`</span>];
db.<span class="fn">execute</span>(query, params);  <span class="comment">// driver escapes the value — injection impossible</span>

<span class="comment">// ✅ SAFE — ORM example (Sequelize)</span>
Product.<span class="fn">findAll</span>({ where: { name: { [Op.like]: <span class="str">`%<span class="good">${userInput}</span>%`</span> } } });

<span class="comment">// ✅ SAFE — Python sqlite3</span>
cursor.<span class="fn">execute</span>(<span class="str">"SELECT * FROM products WHERE name LIKE ?"</span>, (<span class="str">f"%<span class="good">{user_input}</span>%"</span>,))
    </div>

    <hr/>

    <div>
      <div style="font-size:.85rem;font-weight:700;margin-bottom:12px;color:var(--text)">
        🔬 Attack Walkthrough — what happens step by step
      </div>
      <div class="steps">
        <div class="step">
          <div class="step-num red">1</div>
          <p>Attacker types <strong>' OR '1'='1</strong> into the search box.</p>
        </div>
        <div class="step">
          <div class="step-num red">2</div>
          <p><strong>Vulnerable:</strong> The app builds<br/>
          <code style="color:var(--warn)">WHERE name LIKE '%' OR '1'='1%'</code><br/>
          The single-quote closes the LIKE string, then <code>OR '1'='1'</code> is appended — a condition that is always true.</p>
        </div>
        <div class="step">
          <div class="step-num red">3</div>
          <p>The database evaluates the injected logic and returns <strong>every row</strong> in the table — the attacker sees all products, including hidden or restricted ones.</p>
        </div>
        <div class="step">
          <div class="step-num green">4</div>
          <p><strong>Safe mode:</strong> The app sends <code style="color:var(--success)">WHERE name LIKE ?</code> with the <em>literal string</em> <code>' OR '1'='1</code> as the bound parameter. The driver escapes the quotes. No rows match — zero results returned. ✅</p>
        </div>
      </div>
    </div>

  </div>
</div>

<script>
  // ── In-memory product database ──────────────────────────────────────────────
  const PRODUCTS = [
    { id: 1,  name: "Laptop Pro 15",        category: "electronics", price: 1299.99, stock: 24 },
    { id: 2,  name: "Wireless Mouse",        category: "electronics", price:   29.99, stock: 150 },
    { id: 3,  name: "USB-C Hub",             category: "electronics", price:   49.99, stock:  87 },
    { id: 4,  name: "Mechanical Keyboard",   category: "electronics", price:  119.99, stock:  42 },
    { id: 5,  name: "4K Monitor",            category: "electronics", price:  449.99, stock:  18 },
    { id: 6,  name: "Cotton T-Shirt",        category: "clothing",    price:   19.99, stock: 300 },
    { id: 7,  name: "Denim Jeans",           category: "clothing",    price:   59.99, stock: 120 },
    { id: 8,  name: "Running Shirt",         category: "clothing",    price:   34.99, stock:  95 },
    { id: 9,  name: "Winter Jacket",         category: "clothing",    price:  149.99, stock:  40 },
    { id: 10, name: "Coffee Beans 1kg",      category: "food",        price:   18.99, stock: 200 },
    { id: 11, name: "Green Tea Pack",        category: "food",        price:    9.99, stock: 180 },
    { id: 12, name: "Dark Chocolate Bar",    category: "food",        price:    4.99, stock: 500 },
    { id: 13, name: "Protein Powder",        category: "food",        price:   39.99, stock:  60 },
    { id: 14, name: "Hammer Set",            category: "tools",       price:   24.99, stock:  75 },
    { id: 15, name: "Screwdriver Kit",       category: "tools",       price:   34.99, stock:  90 },
    { id: 16, name: "Power Drill",           category: "tools",       price:   89.99, stock:  30 },
    { id: 17, name: "JavaScript: The Good Parts", category: "books",  price:   29.99, stock:  55 },
    { id: 18, name: "Clean Code",            category: "books",       price:   34.99, stock:  48 },
    { id: 19, name: "Design Patterns",       category: "books",       price:   44.99, stock:  33 },
    { id: 20, name: "Secret Admin Record",   category: "electronics", price:    0.00, stock:   1 },
  ];

  // ── Injection detection helpers ─────────────────────────────────────────────
  const INJECTION_PATTERNS = [
    /'\s*or\s*/i,
    /'\s*and\s*/i,
    /--/,
    /;\s*(drop|delete|update|insert|create|alter|truncate)/i,
    /union\s+select/i,
    /'\s*=\s*'/i,
    /1\s*=\s*1/i,
    /'\s*or\s+1/i,
  ];

  function detectInjection(input) {
    return INJECTION_PATTERNS.some(p => p.test(input));
  }

  // ── Vulnerable "query engine" ────────────────────────────────────────────────
  // Simulates what a real SQL engine would do with a concatenated query.
  // We parse a very small subset: LIKE '%...%' and OR conditions.
  function vulnerableSearch(rawInput) {
    // Build the "SQL" string exactly as a vulnerable app would
    const builtQuery = `SELECT * FROM products WHERE name LIKE '%${rawInput}%'`;

    let results = [];
    let injected = false;
    let warning  = "";

    // Simulate injection effects
    const lower = rawInput.toLowerCase();

    // Tautology: OR '1'='1', OR 1=1, OR 'a'='a', OR true, etc.
    const tautology = /'\s*or\s*'[^']+'\s*=\s*'[^']+/i.test(rawInput)
                   || /'\s*or\s+1\s*=\s*1/i.test(rawInput)
                   || /'\s*or\s+true/i.test(rawInput);

    // DROP / destructive
    const destructive = /;\s*(drop|delete|truncate|alter)\s+table/i.test(rawInput);

    // UNION SELECT
    const unionSel = /union\s+select/i.test(rawInput);

    if (destructive) {
      injected = true;
      warning  = "💥 Destructive injection detected! DROP/DELETE/TRUNCATE executed — table would be destroyed in a real DB.";
      results  = [];   // table is "gone"
    } else if (tautology) {
      injected = true;
      warning  = "🚨 Tautology injection! Condition always TRUE — all rows returned (including hidden records).";
      results  = [...PRODUCTS];  // all rows leak
    } else if (unionSel) {
      injected = true;
      warning  = "🚨 UNION injection! In a real DB this could merge results from any other table (users, passwords, etc.).";
      // Simulate leaking extra "shadow" data
      results  = PRODUCTS.filter(p =>
        p.name.toLowerCase().includes(rawInput.split("'")[0].toLowerCase().trim())
      );
      results  = results.concat([
        { id: 99, name: "[INJECTED] admin / password123", category: "⚠️ leaked", price: 0, stock: 0 },
        { id: 100,name: "[INJECTED] user@example.com",    category: "⚠️ leaked", price: 0, stock: 0 },
      ]);
    } else {
      // Normal (non-injected) path — simple LIKE simulation
      const term = rawInput.replace(/'/g, "").toLowerCase().trim();
      results = term === ""
        ? [...PRODUCTS]
        : PRODUCTS.filter(p => p.name.toLowerCase().includes(term));
    }

    return { builtQuery, results, injected, warning };
  }

  // ── Safe "parameterized" engine ──────────────────────────────────────────────
  function safeSearch(rawInput) {
    // The query structure is FIXED — the placeholder ? is never interpreted as SQL
    const paramQuery = `SELECT * FROM products WHERE name LIKE ?   [param: "%${escapeDisplay(rawInput)}%"]`;

    // Treat the entire input as a literal string — no SQL interpretation
    const term = rawInput.toLowerCase().trim();
    const results = term === ""
      ? [...PRODUCTS]
      : PRODUCTS.filter(p => p.name.toLowerCase().includes(term));

    return { paramQuery, results };
  }

  function escapeDisplay(str) {
    return str.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
  }

  // ── Rendering ────────────────────────────────────────────────────────────────
  function renderRows(tbodyId, rows, isInjected) {
    const tbody = document.getElementById(tbodyId);
    if (!rows || rows.length === 0) {
      tbody.innerHTML = `<tr><td colspan="5" class="empty-state">No products found</td></tr>`;
      return;
    }
    tbody.innerHTML = rows.map(p => {
      const cat   = String(p.category).toLowerCase().replace(/[^a-z]/g,"");
      const price = isNaN(p.price) ? p.price : `$${Number(p.price).toFixed(2)}`;
      const rowStyle = isInjected && (p.id === 99 || p.id === 100 || p.id === 20)
        ? `style="background:rgba(247,95,95,.1)"` : "";
      return `
        <tr ${rowStyle}>
          <td>${p.id}</td>
          <td>${escapeDisplay(String(p.name))}</td>
          <td><span class="badge badge-${cat}">${escapeDisplay(String(p.category))}</span></td>
          <td>${price}</td>
          <td>${p.stock}</td>
        </tr>`;
    }).join("");
  }

  function highlightVulnQuery(raw, term) {
    // Colour the injected portion red
    const safe  = escapeDisplay(raw.split("'")[0]);
    const after = raw.includes("'") ? raw.slice(raw.indexOf("'")) : "";
    const afterHtml = after
      ? `<span class="inj">${escapeDisplay(after)}</span>`
      : `<span class="str">${escapeDisplay(term)}</span>`;

    return `<span class="kw">SELECT</span> * <span class="kw">FROM</span> products `
         + `<span class="kw">WHERE</span> name <span class="kw">LIKE</span> `
         + `<span class="str">'%${safe}</span>${afterHtml}<span class="str">%'</span>`;
  }

  function highlightSafeQuery(rawInput) {
    return `<span class="kw">SELECT</span> * <span class="kw">FROM</span> products `
         + `<span class="kw">WHERE</span> name <span class="kw">LIKE</span> `
         + `<span class="param">?</span>  `
         + `<span style="color:var(--muted)">[param: "</span>`
         + `<span class="param">%${escapeDisplay(rawInput)}%</span>`
         + `<span style="color:var(--muted)">"]</span>`;
  }

  // ── Main search handler ───────────────────────────────────────────────────────
  function runSearch() {
    const rawInput = document.getElementById("searchInput").value;

    // --- Vulnerable side ---
    const { builtQuery, results: vResults, injected, warning } = vulnerableSearch(rawInput);

    document.getElementById("vulnQuery").innerHTML = highlightVulnQuery(rawInput, rawInput);

    const vulnAlert = document.getElementById("vulnAlert");
    if (injected) {
      vulnAlert.className = "alert-banner danger show";
      vulnAlert.innerHTML = `<span>⚠️</span><span>${warning}</span>`;
    } else {
      vulnAlert.className = "alert-banner";
      vulnAlert.innerHTML = "";
    }

    renderRows("vulnResults", vResults, injected);
    document.getElementById("vulnCount").textContent =
      vResults.length > 0 ? `${vResults.length} row(s) returned` : "";

    // --- Safe side ---
    const { paramQuery, results: sResults } = safeSearch(rawInput);

    document.getElementById("safeQuery").innerHTML = highlightSafeQuery(rawInput);

    const safeAlert = document.getElementById("safeAlert");
    if (detectInjection(rawInput)) {
      safeAlert.className = "alert-banner success show";
      safeAlert.innerHTML = `<span>✅</span><span>Injection attempt detected but neutralised — input treated as a literal string.</span>`;
    } else {
      safeAlert.className = "alert-banner";
      safeAlert.innerHTML = "";
    }

    renderRows("safeResults", sResults, false);
    document.getElementById("safeCount").textContent =
      sResults.length > 0 ? `${sResults.length} row(s) returned` : "";
  }

  function setPayload(val) {
    document.getElementById("searchInput").value = val;
    runSearch();
  }

  function clearSearch() {
    document.getElementById("searchInput").value = "";
    runSearch();
  }

  // Allow Enter key
  document.getElementById("searchInput").addEventListener("keydown", e => {
    if (e.key === "Enter") runSearch();
  });

  // Initial render
  runSearch();
</script>
