<script>
    // =========================================================
    // IN-MEMORY DATABASE
    // =========================================================
    const database = {
        products: [
            // Public products
            { id: 1,  name: "Laptop Pro 15",      category: "electronics", price: 1299.99, stock: 45,  visible: true  },
            { id: 2,  name: "Wireless Mouse",      category: "electronics", price: 29.99,  stock: 200, visible: true  },
            { id: 3,  name: "Mechanical Keyboard", category: "electronics", price: 89.99,  stock: 75,  visible: true  },
            { id: 4,  name: "USB-C Hub",           category: "electronics", price: 49.99,  stock: 120, visible: true  },
            { id: 5,  name: "Running Shoes",        category: "sports",     price: 79.99,  stock: 60,  visible: true  },
            { id: 6,  name: "Yoga Mat",             category: "sports",     price: 24.99,  stock: 90,  visible: true  },
            { id: 7,  name: "Coffee Mug",           category: "kitchen",    price: 12.99,  stock: 300, visible: true  },
            { id: 8,  name: "Blender Pro",          category: "kitchen",    price: 59.99,  stock: 40,  visible: true  },
            { id: 9,  name: "Desk Lamp",            category: "furniture",  price: 34.99,  stock: 55,  visible: true  },
            // Hidden / admin records — should NEVER be shown to users
            { id: 10, name: "ADMIN: All User Passwords Hash Dump", category: "admin",  price: 0,     stock: 0,   visible: false },
            { id: 11, name: "SECRET: Internal Pricing Strategy",   category: "admin",  price: 0,     stock: 0,   visible: false },
            { id: 12, name: "CONFIDENTIAL: Employee Salaries",     category: "admin",  price: 0,     stock: 0,   visible: false },
        ]
    };

    let vulnSearchCount = 0;
    let safeSearchCount = 0;

    // =========================================================
    // VULNERABLE SEARCH — Simulates string concatenation
    // =========================================================
    function runVulnerableSearch() {
        const rawInput = document.getElementById('vulnInput').value;
        vulnSearchCount++;
        document.getElementById('vulnSearchCount').textContent = vulnSearchCount;

        const attackResult = document.getElementById('vulnAttackResult');
        const attackMsg = document.getElementById('vulnAttackMsg');
        attackResult.classList.remove('show');

        // Simulate the SQL query string (for display)
        const simulatedSQL = buildVulnerableQueryDisplay(rawInput);
        document.getElementById('vulnQuery').innerHTML = simulatedSQL;

        // Simulate what happens when input is used without sanitization
        const { results, wasInjected, injectionType } = vulnerableFilter(rawInput);

        if (wasInjected) {
            attackResult.classList.add('show');
            attackMsg.innerHTML = injectionType;
        }

        renderResults('vulnResults', 'vulnResultCount', results, true);
    }

    function buildVulnerableQueryDisplay(input) {
        const escaped = escapeHtmlForDisplay(input);
        const isInjection = detectInjectionType(input);

        if (!input) {
            return `<span class="sql-keyword">SELECT</span> <span class="sql-normal">* FROM products WHERE visible = 1</span>`;
        }

        let inputDisplay;
        if (isInjection) {
            inputDisplay = `<span class="sql-injected">${escaped}</span>`;
        } else {
            inputDisplay = `<span class="sql-string">${escaped}</span>`;
        }

        return `<span class="sql-keyword">SELECT</span> <span class="sql-normal">* FROM products</span><br>` +
               `<span class="sql-keyword">WHERE</span> <span class="sql-normal">name LIKE </span><span class="sql-string">'%</span>${inputDisplay}<span class="sql-string">%'</span>`;
    }

    function vulnerableFilter(input) {
        if (!input.trim()) {
            const results = database.products.filter(p => p.visible);
            return { results, wasInjected: false, injectionType: '' };
        }

        const lowerInput = input.toLowerCase().trim();
        let wasInjected = false;
        let injectionType = '';
        let results = [];

        // Detect and simulate various injection patterns
        if (
            lowerInput.includes("' or '1'='1") ||
            lowerInput.includes("' or 1=1") ||
            lowerInput.includes("or 1=1") ||
            lowerInput.includes("or '1'='1")
        ) {
            // Classic OR injection — returns ALL records including hidden
            results = [...database.products];
            wasInjected = true;
            injectionType = `<strong>' OR '1'='1 attack:</strong> The condition <code>WHERE name LIKE '%...' OR '1'='1%'</code> is always TRUE, so every single row is returned — including hidden admin records!`;
        }
        else if (lowerInput.includes("category='admin'") || lowerInput.includes('category="admin"')) {
            // Category dump injection
            results = database.products.filter(p => p.category === 'admin');
            wasInjected = true;
            injectionType = `<strong>Category injection:</strong> Attacker injected a new WHERE condition to specifically target the 'admin' category, dumping confidential records!`;
        }
        else if (lowerInput.includes('drop table') || lowerInput.includes('drop database')) {
            // Destructive injection (simulated)
            results = [];
            wasInjected = true;
            injectionType = `<strong>DROP TABLE attack detected!</strong> In a real database, this would <strong>permanently delete</strong> the entire products table! Query: <code>SELECT * FROM products WHERE name LIKE '%'; DROP TABLE products; --%'</code>`;
        }
        else if (lowerInput.includes('--') || lowerInput.includes('/*')) {
            // Comment injection
            results = database.products.filter(p => p.visible);
            wasInjected = true;
            injectionType = `<strong>SQL comment injection:</strong> The <code>--</code> or <code>/* */</code> comments out the rest of the query, potentially removing security conditions like <code>AND visible=1</code>.`;
        }
        else if (lowerInput === '%') {
            // Wildcard — returns all visible (in LIKE context this matches everything)
            results = database.products.filter(p => p.visible);
            wasInjected = false;
        }
        else if (lowerInput.includes("'")) {
            // Quote in input — potential injection attempt, show partial results
            const cleanPart = lowerInput.split("'")[0];
            results = database.products.filter(p =>
                p.visible && p.name.toLowerCase().includes(cleanPart)
            );
            wasInjected = true;
            injectionType = `<strong>Quote injection attempt:</strong> The single quote <code>'</code> breaks out of the string literal. In a real DB this might cause a syntax error or, with the right payload, full data exposure.`;
        }
        else {
            // Normal search — only visible products
            results = database.products.filter(p =>
                p.visible && p.name.toLowerCase().includes(lowerInput)
            );
        }

        return { results, wasInjected, injectionType };
    }

    // =========================================================
    // SAFE SEARCH — Simulates parameterized queries
    // =========================================================
    function runSafeSearch() {
        const rawInput = document.getElementById('safeInput').value;
        safeSearchCount++;
        document.getElementById('safeSearchCount').textContent = safeSearchCount;

        const safeBlockResult = document.getElementById('safeBlockResult');
        const safeBlockMsg = document.getElementById('safeBlockMsg');
        safeBlockResult.classList.remove('show');

        // Show the parameterized query (structure never changes)
        const queryDisplay = buildSafeQueryDisplay(rawInput);
        document.getElementById('safeQuery').innerHTML = queryDisplay;

        // Detect if this was an injection attempt
        const injectionDetected = detectInjectionType(rawInput);

        // Safe filter — input is ALWAYS treated as literal data
        const results = safeFilter(rawInput);

        if (injectionDetected && rawInput.trim()) {
            safeBlockResult.classList.add('show');
            safeBlockMsg.innerHTML = `Input <code>${escapeHtmlForDisplay(rawInput)}</code> was treated as a <strong>literal search string</strong>, not as SQL code. The query structure is fixed — user input can only affect the <code>?</code> value, never the query logic. Result: ${results.length} product(s) found matching that exact text.`;
        }

        renderResults('safeResults', 'safeResultCount', results, false);
    }

    function buildSafeQueryDisplay(input) {
        // The query structure NEVER changes — only the parameter value changes
        const paramValue = input ? `<span class="sql-string">'%${escapeHtmlForDisplay(input)}%'</span>` : `<span class="sql-string">''</span>`;
        return `<span class="sql-keyword">SELECT</span> <span class="sql-normal">* FROM products</span><br>` +
               `<span class="sql-keyword">WHERE</span> <span class="sql-normal">visible = 1</span><br>` +
               `<span class="sql-keyword">AND</span> <span class="sql-normal">name LIKE </span><span class="sql-param">?</span><br>` +
               `<span class="comment" style="color:#6e7681">-- Params: [${paramValue}]</span><br>` +
               `<span class="comment" style="color:#6e7681">-- Input is data only, never SQL code ✅</span>`;
    }

    function safeFilter(input) {
        if (!input.trim()) {
            return database.products.filter(p => p.visible);
        }

        // The input is ALWAYS treated as a literal string — no SQL interpretation
        // Special characters are just characters, not SQL operators
        const literalSearch = input.toLowerCase();

        return database.products.filter(p =>
            p.visible && p.name.toLowerCase().includes(literalSearch)
        );
        // Note: Even "' OR '1'='1" is searched as the literal text "' or '1'='1"
        // which matches nothing in our product names → 0 results, injection fails!
    }

    // =========================================================
    // HELPERS
    // =========================================================
    function detectInjectionType(input) {
        if (!input) return false;
        const lower = input.toLowerCase();
        return (
            lower.includes("'") ||
            lower.includes('"') ||
            lower.includes(' or ') ||
            lower.includes(' and ') ||
            lower.includes('--') ||
            lower.includes('/*') ||
            lower.includes(';') ||
            lower.includes('drop ') ||
            lower.includes('select ') ||
            lower.includes('union ') ||
            lower.includes('insert ') ||
            lower.includes('delete ') ||
            lower.includes('update ') ||
            lower.includes('1=1') ||
            lower.includes('1 = 1')
        );
    }

    function escapeHtmlForDisplay(str) {
        return str
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#39;');
    }

    function renderResults(containerId, countId, results, isVulnerable) {
        const container = document.getElementById(containerId);
        const countEl = document.getElementById(countId);

        if (!results || results.length === 0) {
            countEl.textContent = '0 results found';
            container.innerHTML = `<div class="no-results">No products found matching your search</div>`;
            return;
        }

        countEl.textContent = `${results.length} result(s) found`;

        let html = `<table class="results-table">
            <thead>
                <tr>
                    <th>ID</th>
                    <th>Product Name</th>
                    <th>Category</th>
                    <th>Price</th>
                    <th>Stock</th>
                </tr>
            </thead>
            <tbody>`;

        results.forEach(product => {
            const isSecret = !product.visible;
            const nameDisplay = isSecret
                ? `${escapeHtmlForDisplay(product.name)} <span class="tag tag-secret">HIDDEN</span>`
                : escapeHtmlForDisplay(product.name);
            const categoryDisplay = isSecret
                ? `<span class="tag tag-admin">${product.category}</span>`
                : `<span class="category">${product.category}</span>`;
            const priceDisplay = isSecret
                ? `<span style="color:#fc8181">⚠️ LEAKED</span>`
                : `<span class="price">$${product.price.toFixed(2)}</span>`;

            html += `<tr style="${isSecret ? 'background:rgba(248,81,73,0.05);' : ''}">
                <td>${product.id}</td>
                <td>${nameDisplay}</td>
                <td>${categoryDisplay}</td>
                <td>${priceDisplay}</td>
                <td>${product.stock}</td>
            </tr>`;
        });

        html += `</tbody></table>`;
        container.innerHTML = html;
    }

    function setVulnInput(value) {
        document.getElementById('vulnInput').value = value;
        runVulnerableSearch();
    }

    function setSafeInput(value) {
        document.getElementById('safeInput').value = value;
        runSafeSearch();
    }

    // Initialize with default state
    document.getElementById('totalProducts').textContent = database.products.length;
    document.getElementById('hiddenRecords').textContent = database.products.filter(p => !p.visible).length;

    // Allow Enter key to trigger search
    document.getElementById('vulnInput').addEventListener('keydown', e => {
        if (e.key === 'Enter') runVulnerableSearch();
    });
    document.getElementById('safeInput').addEventListener('keydown', e => {
        if (e.key === 'Enter') runSafeSearch();
    });
</script>
</body>
</html>
```

## What This Demo Does

### 🔴 Vulnerable Panel
- Simulates **string concatenation** query building
- Injection payloads like `' OR '1'='1` bypass filters and **expose hidden admin records**
- `DROP TABLE` and comment injections (`--`) are also simulated
- The constructed "SQL string" is displayed so you can see exactly how it breaks

### 🟢 Safe Panel
- Simulates **parameterized queries** — the query structure is fixed
- The **same payloads produce 0 results** because input is treated as literal data
- Shows the placeholder `?` syntax and explains why it's safe

### Key Concepts Illustrated
| Concept | Vulnerable | Safe |
|---|---|---|
| Query building | String concat | Template + params |
| User input role | **SQL code** | **Data only** |
| `' OR '1'='1` | Dumps all rows | Searches literally |
| Hidden records | **Exposed** | Protected |

