    // injected OR conditions, simulating a real SQL injection.
    // =========================================================
    function runVulnerableSearch() {
        const input = document.getElementById('vulnerableInput').value;
        const queryDisplay = document.getElementById('vulnerableQueryDisplay');
        const queryText = document.getElementById('vulnerableQueryText');
        const statusEl = document.getElementById('vulnerableStatus');
        const countEl = document.getElementById('vulnerableCount');
        const resultsEl = document.getElementById('vulnerableResults');

        // Simulate the constructed SQL query string
        const simulatedQuery = `SELECT * FROM products WHERE name LIKE '%${input}%'`;

        // Detect injection attempts
        const injectionPatterns = [
            /'\s*or\s*/i,
            /'\s*and\s*/i,
            /--/,
            /;\s*(drop|delete|insert|update)/i,
            /union\s+select/i,
            /1\s*=\s*1/i,
            /'\s*or\s*secret/i
        ];
        const isInjection = injectionPatterns.some(p => p.test(input));

        // Update query display
        if (isInjection) {
            queryDisplay.className = 'query-display injected';
            const highlighted = escapeHtml(simulatedQuery).replace(
                escapeHtml(input),
                `<span class="highlight">${escapeHtml(input)}</span>`
            );
            queryText.innerHTML = highlighted;
        } else {
            queryDisplay.className = 'query-display';
            queryText.innerHTML = escapeHtml(simulatedQuery);
        }

        // Execute the "vulnerable" filter
        const results = vulnerableFilter(input);

        // Update status
        if (isInjection && results.length > 0) {
            const hasSecrets = results.some(r => r.secret);
            statusEl.className = 'attack-status warning';
            statusEl.innerHTML = `
                <span class="injection-indicator indicator-danger"></span>
                <span>⚠️ INJECTION DETECTED! Returned ${results.length} rows${hasSecrets ? ' — including <strong>SECRET data!</strong>' : ''}. Attack succeeded.</span>
            `;
            countEl.className = 'results-count count-danger';
        } else if (input === '') {
            statusEl.className = 'attack-status normal';
            statusEl.innerHTML = '<span>Enter a search term to begin</span>';
            countEl.className = 'results-count count-normal';
        } else {
            statusEl.className = 'attack-status normal';
            statusEl.innerHTML = `<span>🔍 Normal search for "${escapeHtml(input)}" — found ${results.length} result(s)</span>`;
            countEl.className = 'results-count count-normal';
        }

        countEl.textContent = `${results.length} row${results.length !== 1 ? 's' : ''}`;
        renderResults(resultsEl, results, true);
    }

    // =========================================================
    // SAFE SEARCH — Simulates parameterized query behavior
    // The input is treated as pure data — SQL operators in the
    // input string are searched for literally, not interpreted.
    // =========================================================
    function runSafeSearch() {
        const input = document.getElementById('safeInput').value;
        const queryText = document.getElementById('safeQueryText');
        const statusEl = document.getElementById('safeStatus');
        const countEl = document.getElementById('safeCount');
        const resultsEl = document.getElementById('safeResults');

        // Show parameterized query — the ? placeholder is separate from data
        queryText.innerHTML = `SELECT * FROM products WHERE name LIKE <span class="param">?</span><br>` +
            `<span style="color:#6060a0">Parameter [1]:</span> <span class="param">${escapeHtml('%' + input + '%')}</span>`;

        // Safe filter: input is treated as literal text only
        const results = safeFilter(input);

        // Detect if user tried injection
        const injectionPatterns = [/'\s*or\s*/i, /--/, /union\s+select/i, /1\s*=\s*1/i];
        const triedInjection = injectionPatterns.some(p => p.test(input));

        if (input === '') {
            statusEl.className = 'attack-status normal';
            statusEl.innerHTML = '<span>Enter a search term to begin</span>';
            countEl.className = 'results-count count-normal';
        } else if (triedInjection) {
            statusEl.className = 'attack-status blocked';
            statusEl.innerHTML = `
                <span class="injection-indicator indicator-safe"></span>
                <span>🛡️ INJECTION BLOCKED! Input treated as literal text. Found ${results.length} matching product name(s).</span>
            `;
            countEl.className = 'results-count count-safe';
        } else {
            statusEl.className = 'attack-status blocked';
            statusEl.innerHTML = `<span>✅ Safe search for "${escapeHtml(input)}" — found ${results.length} result(s)</span>`;
            countEl.className = 'results-count count-safe';
        }

        countEl.textContent = `${results.length} row${results.length !== 1 ? 's' : ''}`;
        renderResults(resultsEl, results, false);
    }

    // =========================================================
    // VULNERABLE FILTER
    // Mimics SQL string concatenation behavior.
    // Parses injected OR conditions to simulate real SQL behavior.
    // =========================================================
    function vulnerableFilter(input) {
        if (input === '') return [];

        const lowerInput = input.toLowerCase();

        // Simulate DROP TABLE injection
        if (/;\s*(drop|delete)\s+table/i.test(input)) {
            // In a real DB this would destroy data — we just simulate the attempt
            return [{
                id: '!',
                name: '[SIMULATED] Table would be DROPPED in real DB',
                category: 'ATTACK',
                price: 0,
                secret: false,
                isAttack: true
            }];
        }

        // Simulate UNION SELECT injection
        if (/union\s+select/i.test(input)) {
            return productDatabase.map(p => ({ ...p, injectedVia: 'UNION' }));
        }

        // Check for OR tautology (1=1, '1'='1', etc.)
        const hasTautology = /1\s*=\s*1/i.test(input) ||
                             /'1'\s*=\s*'1'/i.test(input) ||
                             /''\s*=\s*''/i.test(input);

        // Check for OR injection pattern
        const hasOrInjection = /'\s*or\s+/i.test(input);

        // Check for secret targeting
        const targetsSecret = /secret\s*=\s*true/i.test(input) ||
                              /secret\s*=\s*1/i.test(input);

        if (hasTautology || (hasOrInjection && !targetsSecret)) {
            // OR 1=1 type: return everything
            return productDatabase;
        }

        if (targetsSecret) {
            return productDatabase.filter(p => p.secret);
        }

        // Check for ' OR name LIKE pattern
        const orNameMatch = input.match(/'\s*or\s+name\s+like\s+'%([^%]*)%'/i);
        if (orNameMatch) {
            const extra = orNameMatch[1].toLowerCase();
            return productDatabase.filter(p =>
                p.name.toLowerCase().includes(extra)
            );
        }

        // Extract the actual search term before any injection
        // e.g., "laptop' OR..." → search for "laptop" AND apply injection
        const beforeInjection = input.split(/'\s*or\s*/i)[0].replace(/'/g, '').toLowerCase();
        const afterHasOr = /'\s*or\s*/i.test(input);

        if (afterHasOr && beforeInjection) {
            // Partial injection: returns items matching the real term + all from OR
            const baseResults = productDatabase.filter(p =>
                p.name.toLowerCase().includes(beforeInjection)
            );
            return [...new Set([...baseResults, ...productDatabase])];
        }

        // Normal (non-injected) search
        return productDatabase.filter(p =>
            p.name.toLowerCase().includes(lowerInput) && !p.secret
        );
    }

    // =========================================================
    // SAFE FILTER
    // Treats the entire input as a literal string to search for.
    // SQL operators in the input are NOT interpreted.
    // =========================================================
    function safeFilter(input) {
        if (input === '') return [];
        // The input is used as-is — a literal substring match
        // SQL keywords like OR, AND, DROP are just characters here
        const lowerInput = input.toLowerCase();
        return productDatabase.filter(p =>
            p.name.toLowerCase().includes(lowerInput) && !p.secret
        );
    }

    // =========================================================
    // RENDER RESULTS TABLE
    // =========================================================
    function renderResults(tbody, results, isVulnerable) {
        if (results.length === 0) {
            tbody.innerHTML = '<tr><td colspan="5" class="no-results">No products found</td></tr>';
            return;
        }

        tbody.innerHTML = results.map(row => {
            const isSecret = row.secret;
            const rowStyle = isSecret ? 'background:#2a0a0a;' : '';
            const secretBadge = isSecret
                ? '<span style="color:#ff4444;font-weight:700;">🔴 EXPOSED!</span>'
                : '<span style="color:#44aa66;">✓ No</span>';

            return `
                <tr style="${rowStyle}">
                    <td>${escapeHtml(String(row.id))}</td>
                    <td style="${isSecret ? 'color:#ff8888;font-weight:600;' : ''}">${escapeHtml(row.name)}</td>
                    <td><span class="category" style="${isSecret ? 'background:#3d1a1a;color:#ff8888;' : ''}">${escapeHtml(row.category)}</span></td>
                    <td class="price">${isSecret ? '—' : '$' + row.price.toFixed(2)}</td>
                    <td>${secretBadge}</td>
                </tr>
            `;
        }).join('');
    }

    // =========================================================
    // UTILITY: HTML escape to prevent XSS in the demo itself
    // =========================================================
    function escapeHtml(str) {
        return String(str)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#39;');
    }

    // =========================================================
    // SYNC INPUTS: typing in one box mirrors to the other
    // so users can easily compare side by side
    // =========================================================
    document.getElementById('vulnerableInput').addEventListener('input', function() {
        // Don't sync — let them be independent for experimentation
    });

    // Initialize
    buildPresets();
</script>
</body>
</html>
```

## What This Demo Does

### 🎯 Core Features

| Feature | Details |
|---|---|
| **In-memory DB** | 13 products including 3 "secret" admin records that should never be exposed |
| **Vulnerable mode** | Simulates string concatenation — injection payloads are interpreted as SQL logic |
| **Safe mode** | Simulates parameterized queries — injection payloads are treated as literal text |
| **Live query display** | Shows the constructed query (vulnerable) vs. the `?` placeholder + parameter (safe) |
| **8 preset payloads** | One-click attack scenarios from classic `OR '1'='1'` to `UNION SELECT` and `DROP TABLE` |

### 🔍 How the Simulation Works

- **Vulnerable filter** parses injected `OR`, tautologies (`1=1`), `UNION SELECT`, `DROP TABLE`, and secret-targeting patterns — returning all rows or secret data when attacked
- **Safe filter** always does a plain `.includes()` substring match on the raw input string — SQL keywords become literal characters to search for
- Secret rows (marked with 🔴 EXPOSED!) only appear in the vulnerable mode when attacked

