        v.textContent = p.label;
        v.title = p.desc;
        v.onclick = () => {
            document.getElementById('vulnInput').value = p.value;
            runVulnSearch();
        };
        vulnDiv.appendChild(v);

        const s = document.createElement('div');
        s.className = 'chip';
        s.textContent = p.label;
        s.title = p.desc;
