            document.getElementById('safeInput').value = p.value;
            runSafeSearch();
        };
        safeDiv.appendChild(s);
    });
}

// ============================================================
//  VULNERABLE SEARCH — Simulates string concatenation
//  This mirrors exactly what happens in real vulnerable code:
//  the input is parsed as part of the query logic.
// ============================================================
function runVulnSearch() {
    const raw = document.getElementById('vulnInput').value;
    const queryEl = document.getElementById('vulnQuery');
    const resultsEl = document.getElementById('vulnResults');
    const countEl = document.getElementById('vulnCount');
    const alertEl = document.getElementById('vulnInjectionAlert');
    const alertMsg = document.getElementById('vulnInjectionMsg');

    // Show the "constructed" query string exactly as a real DB would see it
    const constructedSQL = `SELECT * FROM products WHERE name LIKE '%${raw}%'`;

    // Detect injection patterns to annotate the display
    const injectionPatterns = [
        /'\s*OR\s*/i,
        /'\s*AND\s*/i,
        /--/,
        /;/,
        /UNION/i,
        /DROP/i,
        /SELECT.*FROM/i,
    ];
    const isInjection = injectionPatterns.some(p => p.test(raw));

    // Render the query with syntax highlighting
    queryEl.innerHTML = `<div class="label">Constructed Query (what the DB engine sees)</div>
        <span class="sql-keyword">SELECT</span> * <span class="sql-keyword">FROM</span> products
        <span class="sql-keyword">WHERE</span> name <span class="sql-keyword">LIKE</span>
        '<span class="sql-string">%</span><span class="${isInjection ? 'sql-injected' : 'sql-string'}">${escapeHtml(raw)}</span><span class="sql-string">%</span>'`;

    // ── SIMULATE VULNERABLE EXECUTION ──────────────────────
    // This is the key educational part: we actually interpret the
    // injected SQL logic, just as a real DB parser would.
    let results = [];
    let injectionType = null;

    // Check for UNION-based injection targeting users table
    if (/UNION\s+SELECT.*FROM\s+users/i.test(raw)) {
        injectionType = 'union';
        // Simulate UNION — attacker gets users table data
        results = DATABASE.users.map(u => ({
            id: u.id,
            name: u.username,
            category: u.password_hash,
            price: u.role,
            stock: u.email,
            _leaked: true
        }));
    }
    // Check for DROP TABLE
    else if (/DROP\s+TABLE/i.test(raw)) {
        injectionType = 'drop';
        results = [];
    }
    // Check for tautology (OR 1=1 style — always true)
    else if (/'\s*OR\s*['"\d]/i.test(raw) || /OR\s+1\s*=\s*1/i.test(raw) || /OR\s+''\s*=\s*''/i.test(raw)) {
        injectionType = 'tautology';
        results = [...DATABASE.products]; // ALL rows returned
    }
    // Check for comment injection
    else if (/--/.test(raw)) {
        const beforeComment = raw.split('--')[0].replace(/^'/, '').trim();
        injectionType = 'comment';
        if (beforeComment === '' || /OR\s*1\s*=\s*1/i.test(beforeComment)) {
            results = [...DATABASE.products];
        } else {
            results = DATABASE.products.filter(p =>
                p.name.toLowerCase().includes(beforeComment.toLowerCase())
            );
        }
    }
    // Normal LIKE behavior (possibly with % wildcard)
    else {
        results = DATABASE.products.filter(p =>
            p.name.toLowerCase().includes(raw.toLowerCase()) ||
            (raw === '%') // wildcard matches all
        );
        if (raw === '%') results = [...DATABASE.products];
    }

    // Show injection alert
    if (isInjection) {
        alertEl.classList.add('show');
        if (injectionType === 'union') {
            alertMsg.textContent = '🚨 UNION injection succeeded — users table (passwords, roles, emails) exposed!';
        } else if (injectionType === 'drop') {
            alertMsg.textContent = '💥 DROP TABLE injection — in a real DB, this would destroy the products table!';
        } else if (injectionType === 'tautology') {
            alertMsg.textContent = `⚠️ Tautology injection — WHERE clause is always TRUE, all ${results.length} rows returned!`;
        } else if (injectionType === 'comment') {
            alertMsg.textContent = '⚠️ Comment injection — SQL comment (--) terminated your intended query logic!';
        } else {
            alertMsg.textContent = '⚠️ Injection pattern detected in query!';
        }
    } else {
        alertEl.classList.remove('show');
    }

    // Render results
    renderResults(resultsEl, countEl, results, isInjection, injectionType);
}

// ============================================================
//  SAFE SEARCH — Simulates parameterized query behavior
//  Input is bound as a value AFTER query structure is compiled.
//  No amount of SQL syntax in the input changes query behavior.
// ============================================================
function runSafeSearch() {
    const raw = document.getElementById('safeInput').value;
    const queryEl = document.getElementById('safeQuery');
    const resultsEl = document.getElementById('safeResults');
    const countEl = document.getElementById('safeCount');

    // Show the parameterized query — structure is fixed, value is separate
    queryEl.innerHTML = `<div class="label">Parameterized Query + Parameter Binding</div>
<span class="sql-keyword">SELECT</span> * <span class="sql-keyword">FROM</span> products
<span class="sql-keyword">WHERE</span> name <span class="sql-keyword">LIKE</span> <span class="sql-param">?</span>
<br><br><span style="color:#8b949e">Parameter[0] bound as string literal:</span>
<span class="sql-safe">→ "%${escapeHtml(raw)}%"</span>
<br><span style="color:#8b949e; font-size:0.78rem">
Query structure compiled before value seen.
Quotes/keywords in value are inert characters.</span>`;

    // ── SAFE EXECUTION ──────────────────────────────────────
    // The user's input is ONLY used as a literal string value.
    // We search for the exact literal text, including any SQL syntax characters.
    // ' OR '1'='1 is searched as the string "' OR '1'='1" — not parsed as SQL.
    const searchTerm = raw.toLowerCase();
    const results = DATABASE.products.filter(p =>
        p.name.toLowerCase().includes(searchTerm)
    );

    // Render results — no injection possible
    renderResults(resultsEl, countEl, results, false, null);
}

