//  RENDER RESULTS TABLE
// ============================================================
function renderResults(container, countEl, rows, isInjection, injectionType) {
    if (rows.length === 0) {
        if (injectionType === 'drop') {
            container.innerHTML = `<div class="empty-state" style="color:#ff6b6b">
                💥 DROP TABLE executed — table destroyed (simulated)<br>
                <span style="font-size:0.75rem;color:#8b949e;margin-top:6px;display:block">In a real DB, this table would be gone</span>
            </div>`;
        } else {
            container.innerHTML = `<div class="empty-state">No results found — input treated as literal search term</div>`;
        }
        countEl.textContent = '0 rows';
        countEl.className = 'result-count normal';
        return;
    }

    const isLeaked = rows[0]?._leaked;
    const cols = isLeaked
        ? ['id', 'name', 'category', 'price', 'stock']
        : ['id', 'name', 'category', 'price', 'stock'];

    const colLabels = isLeaked
        ? ['id', 'username ⚠️', 'password_hash ⚠️', 'role ⚠️', 'email ⚠️']
        : ['ID', 'Name', 'Category', 'Price', 'Stock'];

    let html = `<table class="results-table"><thead><tr>`;
    colLabels.forEach(c => { html += `<th>${c}</th>`; });
    html += `</tr></thead><tbody>`;

    rows.forEach(row => {
        html += `<tr>`;
        cols.forEach((col, i) => {
            let val = row[col] ?? '—';
            let cls = '';
            if (col === 'id') cls = 'id';
            if (col === 'price') cls = isLeaked ? 'sensitive' : 'price';
            if (isLeaked && (col === 'category' || col === 'price' || col === 'stock')) cls = 'sensitive';
            if (isLeaked && col === 'name') cls = 'sensitive';
            if (!isLeaked && col === 'price') { val = `$${Number(val).toFixed(2)}`; cls = 'price'; }
            html += `<td class="${cls}">${escapeHtml(String(val))}</td>`;
        });
        html += `</tr>`;
    });

    html += `</tbody></table>`;
    container.innerHTML = html;

    if (isInjection && rows.length > 3) {
        countEl.textContent = `${rows.length} rows ← INJECTED`;
        countEl.className = 'result-count danger';
    } else {
        countEl.textContent = `${rows.length} row${rows.length !== 1 ? 's' : ''}`;
        countEl.className = 'result-count normal';
    }
}

