    const cols = Object.keys(data[0]);
    const sensitiveFields = ['password_hash', 'email', 'role'];

    let html = `<table class="results-table"><thead><tr>`;
    cols.forEach(c => {
        const isSensitive = sensitiveFields.includes(c);
        html += `<th style="${isSensitive ? 'color:#ff6b6b' : ''}">${c}${isSensitive ? ' 🔒' : ''}</th>`;
    });
    html += `</tr></thead><tbody>`;

    data.forEach(row => {
        html += `<tr>`;
        cols.forEach(col => {
            const isSensitive = sensitiveFields.includes(col);
            html += `<td class="${isSensitive ? 'sensitive' : col === 'price' || col === 'total' ? 'price' : col === 'id' || col === 'user_id' || col === 'product_id' ? 'id' : ''}">${escapeHtml(String(row[col]))}</td>`;
        });
        html += `</tr>`;
    });

    html += `</tbody></table>`;
    document.getElementById('dbTableContainer').innerHTML = html;
}

// ============================================================
//  UTILITY
// ============================================================
function escapeHtml(str) {
    return str
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

// Enter key support
