let currentMode = 'vulnerable';

function setMode(mode) {
    currentMode = mode;
    document.getElementById('btnVuln').classList.toggle('active', mode === 'vulnerable');
    document.getElementById('btnSafe').classList.toggle('active', mode === 'safe');
    const ind = document.getElementById('modeIndicator');
    if (mode === 'vulnerable') {
        ind.className = 'mode-indicator vulnerable';
        ind.textContent = '☠ VULNERABLE — Query built by string concatenation. Your input becomes SQL code.';
    } else {
        ind.className = 'mode-indicator safe';
        ind.textContent = '🛡 SAFE — Parameterized query. Input is always treated as data, never as SQL code.';
    }
    runQuery();
}

function loadPreset(search, price) {
    document.getElementById('searchInput').value = search;
    document.getElementById('priceInput').value = price;
    runQuery();
}

// ─── SIMULATED SQL ENGINE ────────────────────────────────────────────────────
// This is the heart of the demo. We actually parse the injected SQL structure
// rather than just doing string matching tricks.

function parseVulnerableQuery(nameInput, priceInput) {
    // Exactly what a vulnerable PHP/Python backend does:
    // "SELECT id,name,category,price FROM products WHERE name LIKE '%" + input + "%' AND price >= " + price
    const rawSQL = `SELECT id,name,category,price FROM products WHERE name LIKE '%${nameInput}%' AND price >= ${priceInput}`;
    return { rawSQL, nameInput, priceInput };
}

function executeVulnerableQuery(nameInput, priceInput) {
    // We genuinely parse the injected SQL structure
    const analysis = analyzeInjection(nameInput, priceInput);
    const results = [];
    let dropped = false;
    let explanation = '';
    let attackType = 'none';

    const ni = nameInput;
    const niUpper = ni.toUpperCase();

    // ── DROP TABLE detection ──
    if (/DROP\s+TABLE/i.test(ni)) {
        dropped = true;
        attackType = 'drop';
        return { results: [], dropped: true, attackType, analysis,
            rawSQL: parseVulnerableQuery(ni, priceInput).rawSQL };
    }

    // ── UNION attack ──
    const unionMatch = ni.match(/'\s*UNION\s+SELECT\s+(.+?)\s+FROM\s+(\w+)(?:\s+WHERE\s+(.+?))?\s*(?:--|$)/i);
    if (unionMatch) {
        attackType = 'union';
        const cols = unionMatch[1].split(',').map(c => c.trim());
        const table = unionMatch[2].toLowerCase();
        const whereClause = unionMatch[3] || null;

        // Get the prefix search (before the quote that starts injection)
        const prefix = ni.split("'")[0];

        // Normal results first (from prefix)
        DB.products.forEach(row => {
            if (row.name.toLowerCase().includes(prefix.toLowerCase()) || prefix === '') {
                results.push({ ...row, _source: 'products', _leaked: false });
            }
        });

        // UNION results
        const sourceTable = DB[table];
        if (sourceTable) {
            const tableKeys = Object.keys(sourceTable[0]);
            let rows = sourceTable;
            // Apply WHERE if present
            if (whereClause) {
                const wm = whereClause.match(/(\w+)\s*=\s*'([^']+)'/i);
                if (wm) {
                    const [, wkey, wval] = wm;
                    rows = rows.filter(r => String(r[wkey]).toLowerCase() === wval.toLowerCase());
                }
            }
            rows.forEach(row => {
                const mapped = {};
                // Map UNION columns to product column names
                const productCols = ['id','name','category','price'];
                cols.forEach((col, i) => {
                    const srcKey = col.trim();
                    mapped[productCols[i] || `col${i}`] = row[srcKey] !== undefined ? row[srcKey] : srcKey;
                });
                results.push({ ...mapped, _source: table, _leaked: true });
            });
        }

        return { results, dropped: false, attackType, analysis,
            rawSQL: parseVulnerableQuery(ni, priceInput).rawSQL };
    }

    // ── OR bypass (tautology) ──
    const orBypass = /'\s*OR\s+/i.test(ni) && !/UNION/i.test(ni);
    if (orBypass) {
        attackType = 'or_bypass';
        // Check if it's a tautology (OR 1=1 or OR '1'='1')
        const isTautology = /OR\s+1\s*=\s*1/i.test(ni) || /OR\s+'1'\s*=\s*'1'/i.test(ni) || /OR\s+'[^']+'\s*=\s*'\1/i.test(ni);
        if (isTautology || /OR\s+'[^']*'\s*=\s*'[^']*'/i.test(ni)) {
            // Dump all products
            DB.products.forEach(row => results.push({ ...row, _source: 'products', _leaked: false }));
        } else {
            DB.products.forEach(row => results.push({ ...row, _source: 'products', _leaked: false }));
        }
        return { results, dropped: false, attackType, analysis,
            rawSQL: parseVulnerableQuery(ni, priceInput).rawSQL };
    }

    // ── Boolean blind ──
    const boolFalse = /AND\s+1\s*=\s*2/i.test(ni);
    const boolTrue  = /AND\s+1\s*=\s*1/i.test(ni);
    if (boolFalse) {
        attackType = 'blind_false';
        return { results: [], dropped: false, attackType, analysis,
            rawSQL: parseVulnerableQuery(ni, priceInput).rawSQL };
    }
    if (boolTrue) {
        attackType = 'blind_true';
        // Strip the injection, return normal results for prefix
        const prefix = ni.split("'")[0];
        DB.products.forEach(row => {
            if (row.name.toLowerCase().includes(prefix.toLowerCase())) {
                results.push({ ...row, _source: 'products', _leaked: false });
            }
        });
        return { results, dropped: false, attackType, analysis,
            rawSQL: parseVulnerableQuery(ni, priceInput).rawSQL };
    }

    // ── LIKE wildcard abuse ──
    const likeAbuse = ni.includes('%') && !ni.includes("'");
    if (likeAbuse) {
        attackType = 'like_wildcard';
        DB.products.forEach(row => {
            // Simulate LIKE with JS regex
            const pattern = ni.replace(/%/g, '.*').replace(/_/g, '.');
            try {
                if (new RegExp(pattern, 'i').test(row.name)) {
                    results.push({ ...row, _source: 'products', _leaked: false });
                }
            } catch(e) {
                results.push({ ...row, _source: 'products', _leaked: false });
            }
        });
        return { results, dropped: false, attackType, analysis,
            rawSQL: parseVulnerableQuery(ni, priceInput).rawSQL };
    }

    // ── Price injection ──
    const priceStr = String(priceInput);
    if (priceStr.includes("'") || /[a-zA-Z]/.test(priceStr) || priceStr.includes(';')) {
        attackType = 'price_injection';
        // Malformed price — return all or error
        if (/OR\s+1\s*=\s*1/i.test(priceStr) || priceStr.trim() === '0 OR 1=1') {
            DB.products.forEach(row => results.push({ ...row, _source: 'products', _leaked: false }));
        }
        return { results, dropped: false, attackType, analysis,
            rawSQL: parseVulnerableQuery(ni, priceStr).rawSQL };
    }

    // ── Normal query ──
    attackType = 'none';
    const minPrice = parseFloat(priceStr) || 0;
    DB.products.forEach(row => {
        if (row.name.toLowerCase().includes(ni.toLowerCase()) && row.price >= minPrice) {
            results.push({ ...row, _source: 'products', _leaked: false });
        }
    });

    return { results, dropped: false, attackType, analysis,
        rawSQL: parseVulnerableQuery(ni, priceInput).rawSQL };
}

function executeSafeQuery(nameInput, priceInput) {
    // Parameterized: input is NEVER parsed as SQL
    // The value is bound as a literal string — quotes, keywords, everything is data
    const minPrice = parseFloat(priceInput);
    const safeMinPrice = isNaN(minPrice) ? 0 : minPrice;
    const results = [];

    DB.products.forEach(row => {
        // LIKE match: input is treated as a literal string, not a pattern with SQL meaning
        // We escape % and _ for LIKE purposes (real parameterized queries do this)
        const literalInput = nameInput; // no SQL parsing happens
        if (row.name.toLowerCase().includes(literalInput.toLowerCase()) && row.price >= safeMinPrice) {
            results.push({ ...row, _source: 'products', _leaked: false });
        }
    });

    return { results, attackType: 'blocked', safeMinPrice };
}

// ─── INJECTION ANALYSIS ─────────────────────────────────────────────────────
function analyzeInjection(nameInput, priceInput) {
    const tokens = [];
    const ni = nameInput;

    if (ni.includes("'")) tokens.push({ type: 'quote_break', text: "Quote breaks out of string context", danger: true });
    if (/\bUNION\b/i.test(ni)) tokens.push({ type: 'union', text: "UNION keyword appends second SELECT", danger: true });
    if (/\bSELECT\b/i.test(ni)) tokens.push({ type: 'select', text: "SELECT keyword — attacker controls columns", danger: true });
    if (/\bFROM\b/i.test(ni)) tokens.push({ type: 'from', text: "FROM keyword — attacker picks the table", danger: true });
    if (/\bWHERE\b/i.test(ni)) tokens.push({ type: 'where', text: "WHERE clause — attacker adds conditions", danger: true });
    if (/\bOR\b/i.test(ni)) tokens.push({ type: 'or', text: "OR operator — can make WHERE always true", danger: true });
    if (/\bAND\b/i.test(ni)) tokens.push({ type: 'and', text: "AND operator — boolean manipulation", danger: false });
    if (/--/.test(ni)) tokens.push({ type: 'comment', text: "-- comment strips everything after it", danger: true });
    if (/\bDROP\b/i.test(ni)) tokens.push({ type: 'ddl', text: "DDL statement — destructive operation", danger: true });
    if (/%/.test(ni)) tokens.push({ type: 'wildcard', text: "% wildcard in LIKE context", danger: false });
    if (tokens.length === 0) tokens.push({ type: 'clean', text: "No SQL metacharacters detected", danger: false });

    return tokens;
}

// ─── RENDER ─────────────────────────────────────────────────────────────────
function runQuery() {
    const nameInput = document.getElementById('searchInput').value;
    const priceInput = document.getElementById('priceInput').value;

    if (currentMode === 'vulnerable') {
        renderVulnerable(nameInput, priceInput);
    } else {
        renderSafe(nameInput, priceInput);
    }
}

function renderVulnerable(nameInput, priceInput) {
    const exec = executeVulnerableQuery(nameInput, priceInput);
    const analysis = analyzeInjection(nameInput, priceInput);

    // ── Query display ──
    const rawSQL = exec.rawSQL;
    const qd = document.getElementById('queryDisplay');

    // Colorize the SQL
    let display = rawSQL
        .replace(/\b(SELECT|FROM|WHERE|UNION|AND|OR|LIKE|DROP|TABLE|INSERT|UPDATE|DELETE|INTO)\b/gi,
            m => `<span class="q-keyword">${m}</span>`);

    // Highlight the injected portion
    if (nameInput.includes("'") || /\b(UNION|OR|AND|DROP|SELECT)\b/i.test(nameInput)) {
        const escaped = nameInput.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        display = display.replace(new RegExp(escaped.replace(/\b(SELECT|FROM|WHERE|UNION|AND|OR|LIKE|DROP|TABLE)\b/gi,
            m => `<span class="q-keyword">${m}</span>`), 'i'),
            `<span class="q-injected">${nameInput}</span>`);
        // Simpler approach: find and wrap the user input
        const safeEscaped = nameInput.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        // Re-render more carefully
        let cleanSQL = rawSQL;
        const parts = cleanSQL.split(nameInput);
        if (parts.length >= 2) {
            const keywordify = s => s.replace(/\b(SELECT|FROM|WHERE|UNION|AND|OR|LIKE|DROP|TABLE|INSERT|UPDATE|DELETE|INTO)\b/gi,
                m => `<span class="q-keyword">${m}</span>`);
            const injectedPart = nameInput.replace(/\b(SELECT|FROM|WHERE|UNION|AND|OR|LIKE|DROP|TABLE|INSERT|UPDATE|DELETE|INTO)\b/gi,
                m => `<span class="q-keyword">${m}</span>`);
            qd.innerHTML = keywordify(parts[0]) +
                `<span class="q-injected" title="INJECTED INPUT">${injectedPart}</span>` +
                keywordify(parts.slice(1).join(nameInput));
        } else {
            qd.innerHTML = display;
        }
    } else {
        qd.innerHTML = display;
    }

    // ── Parse tree / token analysis ──
    const pt = document.getElementById('parseTree');
    pt.innerHTML = '<h4>🌳 Injection Token Analysis</h4>';
    analysis.forEach(tok => {
        pt.innerHTML += `<div class="ast-node ${tok.danger ? 'injected' : 'normal'}">
            <span class="tag ${tok.danger ? 'red' : 'blue'}">${tok.type.toUpperCase()}</span>
            <span class="ast-value ${tok.danger ? 'danger' : ''}">${tok.text}</span>
        </div>`;
    });

    // ── Results ──
    const ra = document.getElementById('resultsArea');
    if (exec.dropped) {
        ra.innerHTML = `<div class="error-result">💥 <strong>DROP TABLE executed.</strong> In a real DB, products table is now gone. All subsequent queries fail.</div>`;
    } else if (exec.results.length === 0) {
        ra.innerHTML = `<div class="empty-result">No rows returned. ${exec.attackType === 'blind_false' ? '(Boolean blind FALSE confirmed — table exists, condition forced false)' : ''}</div>`;
    } else {
        let html = '<table class="result-table"><thead><tr><th>id</th><th>name</th><th>category</th><th>price</th>';
        if (exec.results.some(r => r._leaked)) html += '<th>⚠ source</th>';
        html += '</tr></thead><tbody>';
        exec.results.forEach(row => {
            const cls = row._leaked ? 'leaked' : 'normal';
            html += `<tr class="${cls}">
                <td>${row.id ?? ''}</td>
                <td>${row.name ?? ''}</td>
                <td>${row.category ?? ''}</td>
                <td>${row.price ?? ''}</td>
                ${exec.results.some(r => r._leaked) ? `<td>${row._leaked ? '🔴 '+row._source+' (LEAKED)' : '🟢 products'}</td>` : ''}
            </tr>`;
        });
        html += '</tbody></table>';
        ra.innerHTML = html;
    }

    // ── Explanation ──
    renderExplanation(exec, nameInput, priceInput, 'vulnerable');
}

function renderSafe(nameInput, priceInput) {
    const exec = executeSafeQuery(nameInput, priceInput);

    // ── Query display ──
    const qd = document.getElementById('queryDisplay');
    const safeDisplay = nameInput.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    const safePrice = isNaN(parseFloat(priceInput)) ? '0' : parseFloat(priceInput).toString();
    qd.innerHTML = `<span class="q-keyword">SELECT</span> id,name,category,price <span class="q-keyword">FROM</span> products
<span class="q-keyword">WHERE</span> name <span class="q-keyword">LIKE</span> <span class="q-param">?</span> <span class="q-keyword">AND</span> price &gt;= <span class="q-param">?</span>

<span style="color:#8b949e">-- Parameters bound separately:</span>
<span class="q-param">$1</span> = <span class="q-safe">'%${safeDisplay}%'</span>  <span style="color:#8b949e">← entire string is data, not code</span>
<span class="q-param">$2</span> = <span class="q-safe">${safePrice}</span>`;

    // ── Parse tree ──
    const pt = document.getElementById('parseTree');
    pt.innerHTML = `<h4>🌳 Parameter Binding Analysis</h4>
    <div class="ast-node normal">
        <span class="tag green">STRUCTURE</span>
        <span class="ast-value">Query structure compiled BEFORE input is received</span>
    </div>
    <div class="ast-node normal">
        <span class="tag blue">PARAM $1</span>
        <span class="ast-value">Value: "${nameInput.replace(/</g,'&lt;')}" — treated as string literal, SQL keywords inside are inert</span>
    </div>
    <div class="ast-node normal">
        <span class="tag blue">PARAM $2</span>
        <span class="ast-value">Value: "${safePrice}" — coerced to numeric type, string injection impossible</span>
    </div>
    <div class="ast-node normal">
        <span class="tag green">RESULT</span>
        <span class="ast-value">No injection possible — parser never sees user input as SQL tokens</span>
    </div>`;

    // ── Results ──
    const ra = document.getElementById('resultsArea');
    if (exec.results.length === 0) {
        ra.innerHTML = `<div class="empty-result">No products match "${nameInput.replace(/</g,'&lt;')}" — legitimate empty result.</div>`;
    } else {
        let html = '<table class="result-table"><thead><tr><th>id</th><th>name</th><th>category</th><th>price</th></tr></thead><tbody>';
        exec.results.forEach(row => {
            html += `<tr class="normal"><td>${row.id}</td><td>${row.name}</td><td>${row.category}</td><td>$${row.price}</td></tr>`;
        });
        html += '</tbody></table>';
        ra.innerHTML = html;
    }

    // ── Explanation ──
    renderExplanation(exec, nameInput, priceInput, 'safe');
}

function renderExplanation(exec, nameInput, priceInput, mode) {
    const et = document.getElementById('explanationText');

    if (mode === 'safe') {
        et.innerHTML = `
        <div class="step defense"><span class="tag green">HOW IT WORKS</span> The SQL query is <span class="safe-highlight">pre-compiled</span> with placeholders (<code>?</code>). The database engine locks the query structure before it ever sees your input.</div>
        <div class="step defense"><span class="tag green">INPUT HANDLING</span> Your input <code>${nameInput.replace(/</g,'&lt;').replace(/>/g,'&gt;')}</code> is passed as a <span class="safe-highlight">typed parameter</span>. Even if it contains <code>UNION</code>, <code>OR</code>, <code>--</code>, or quotes, the DB treats it as a string value to search for, not as SQL syntax.</div>
        <div class="step defense"><span class="tag green">TYPE SAFETY</span> The price field is bound as a numeric type. Passing <code>0 OR 1=1</code> as price causes a type error, not a bypass.</div>
        <div class="step defense"><span class="tag green">WHY IT'S UNBREAKABLE</span> The parse tree is fixed. There is no code path where user input can add new SQL tokens. The attacker can't add a UNION, can't add OR, can't comment out anything.</div>`;
        return;
    }

    const attackType = exec.attackType;
    const steps = [];

    if (attackType === 'none') {
        steps.push({ cls: 'defense', text: `<span class="tag blue">NORMAL</span> Input <code>${nameInput}</code> contains no SQL metacharacters. Concatenation happens to be safe here — but only by accident.` });
        steps.push({ cls: 'attack', text: `<span class="tag orange">WARNING</span> This is false safety. The code is still vulnerable. Any input with a single quote will break out of the string context.` });
    } else if (attackType === 'union') {
        steps.push({ cls: 'attack', text: `<span class="tag red">STEP 1</span> The <span class="highlight">'</span> closes the string literal that was wrapping your input.` });
        steps.push({ cls: 'attack', text: `<span class="tag red">STEP 2</span> <span class="highlight">UNION SELECT</span> appends a completely new SELECT statement. The DB engine now executes two queries and merges results.` });
        steps.push({ cls: 'attack', text: `<span class="tag red">STEP 3</span> The attacker specified <span class="highlight">FROM users</span> — a table the application never intended to query.` });
        steps.push({ cls: 'attack', text: `<span class="tag red">STEP 4</span> <span class="highlight">--</span> comments out the rest of the original query (the closing <code>'%' AND price >= 0</code>), preventing syntax errors.` });
        steps.push({ cls: 'attack', text: `<span class="tag red">RESULT</span> Password hashes and roles from the users table are now in the result set. The app code has no idea — it just iterates rows.` });
    } else if (attackType === 'or_bypass') {
        steps.push({ cls: 'attack', text: `<span class="tag red">STEP 1</span> <span class="highlight">'</span> breaks out of the LIKE string.` });
        steps.push({ cls: 'attack', text: `<span class="tag red">STEP 2</span> <span class="highlight">OR 1=1</span> (or OR '1'='1') creates a tautology — a condition that is always true.` });
        steps.push({ cls: 'attack', text: `<span class="tag red">STEP 3</span> The WHERE clause now reads: <code>name LIKE '...' OR [always true]</code>. Every row passes the filter.` });
        steps.push({ cls: 'attack', text: `<span class="tag red">RESULT</span> All products returned regardless of the original search term. Authentication bypass uses the same trick on login queries.` });
    } else if (attackType === 'blind_false') {
        steps.push({ cls: 'attack', text: `<span class="tag orange">BLIND TECHNIQUE</span> No data is extracted directly. Instead, the attacker asks yes/no questions by forcing conditions true or false.` });
        steps.push({ cls: 'attack', text: `<span class="tag red">AND 1=2</span> is always false. Zero rows returned. This confirms the injection point works and the table/column exists.` });
        steps.push({ cls: 'attack', text: `<span class="tag orange">INFERENCE</span> By cycling through conditions like <code>AND SUBSTRING(password,1,1)='a'</code>, attackers extract data one character at a time from the result count.` });
    } else if (attackType === 'blind_true') {
        steps.push({ cls: 'attack', text: `<span class="tag orange">BLIND TECHNIQUE</span> <span class="highlight">AND 1=1</span> is always true — normal results return. Confirms the injection point is live.` });
        steps.push({ cls: 'attack', text: `<span class="tag orange">METHODOLOGY</span> Attacker alternates true/false conditions. Different row counts = data leakage without UNION.` });
    } else if (attackType === 'drop') {
        steps.push({ cls: 'attack', text: `<span class="tag red">DDL INJECTION</span> In some DB configs (SQLite, older MySQL), multiple statements can be stacked with <code>;</code>.` });
        steps.push({ cls: 'attack', text: `<span class="tag red">RESULT</span> The products table is destroyed. No data recovery without backups. This is why DB users should have minimal privileges (no DROP rights).` });
    } else if (attackType === 'like_wildcard') {
        steps.push({ cls: 'attack', text: `<span class="tag orange">WILDCARD ABUSE</span> The <code>%</code> character is a LIKE wildcard meaning "any sequence of characters".` });
        steps.push({ cls: 'attack', text: `<span class="tag orange">RESULT</span> <code>%</code> alone matches everything. Combined with other patterns it can enumerate data without breaking string context.` });
    }

    et.innerHTML = steps.map(s => `<div class="step ${s.cls}">${s.text}</div>`).join('');
}

// ─── INIT ────────────────────────────────────────────────────────────────────
runQuery();
</script>
