<script>
// ─── In-memory database ───────────────────────────────────────────────────────

const DB = {
  products: [
    { id: 1, name: 'Laptop Pro',     category: 'Electronics', price: 1299, stock: 15 },
    { id: 2, name: 'Wireless Mouse', category: 'Electronics', price: 29,   stock: 200 },
    { id: 3, name: 'Standing Desk',  category: 'Furniture',   price: 599,  stock: 8 },
    { id: 4, name: 'USB-C Hub',      category: 'Electronics', price: 49,   stock: 75 },
    { id: 5, name: 'Monitor 4K',     category: 'Electronics', price: 799,  stock: 22 },
  ],
  users: [
    { id: 1, username: 'admin',  password: 's3cr3t!',  email: 'admin@corp.com' },
    { id: 2, username: 'jsmith', password: 'hunter2',  email: 'j@corp.com' },
    { id: 3, username: 'dbroot', password: 'r00tpass', email: 'db@corp.com' },
  ]
};

// ─── SQL Parser / Executor ────────────────────────────────────────────────────
// Simulates the parse tree that a real DB engine would build.
// Handles: SELECT, WHERE LIKE, OR conditions, UNION SELECT, comment stripping.

function parseAndExecute(sql) {
  // Strip inline comments (-- to end of line)
  const stripped = sql.replace(/--[^\n]*/g, '').replace(/\/\*[\s\S]*?\*\//g, '').trim();

  // Split on UNION (case-insensitive)
  const unionParts = stripped.split(/\bUNION\s+(?:ALL\s+)?SELECT\b/i);

  let rows = [];
  let columnNames = [];

  for (let i = 0; i < unionParts.length; i++) {
    const part = (i === 0 ? unionParts[0] : 'SELECT ' + unionParts[i]).trim();
    const result = executeSingleSelect(part);
    if (result.error) return result;
    if (i === 0) columnNames = result.columns;
    rows = rows.concat(result.rows);
  }

  return { rows, columns: columnNames, error: null };
}

function executeSingleSelect(sql) {
  // Match: SELECT <cols> FROM <table> [WHERE <conditions>]
  const m = sql.match(/^\s*SELECT\s+([\s\S]+?)\s+FROM\s+(\w+)(?:\s+WHERE\s+([\s\S]+))?\s*$/i);
  if (!m) return { rows: [], columns: [], error: 'Parse error: cannot parse SELECT statement' };

  const colSpec  = m[1].trim();
  const table    = m[2].trim().toLowerCase();
  const whereClause = m[3] ? m[3].trim() : null;

  if (!DB[table]) return { rows: [], columns: [], error: `Table "${table}" does not exist` };

  const tableData = DB[table];
  const allCols   = Object.keys(tableData[0]);

  // Resolve column list
  let columns;
  if (colSpec === '*') {
    columns = allCols;
  } else {
    columns = colSpec.split(',').map(c => c.trim());
    // Validate columns exist (allow literals like 0, 1 for UNION padding)
    columns = columns.map(c => {
      if (/^\d+$/.test(c)) return '__literal__' + c;
      return c;
    });
  }

  // Filter rows by WHERE
  let filtered = tableData;
  if (whereClause) {
    filtered = tableData.filter(row => evaluateWhere(whereClause, row));
  }

  // Project columns
  const rows = filtered.map(row => {
    const out = {};
    columns.forEach(col => {
      if (col.startsWith('__literal__')) {
        out[col.replace('__literal__', 'val')] = col.replace('__literal__', '');
      } else {
        out[col] = row[col] !== undefined ? row[col] : null;
      }
    });
    return out;
  });

  const displayCols = columns.map(c => c.startsWith('__literal__') ? c.replace('__literal__', 'val') : c);
  return { rows, columns: displayCols, error: null };
}

function evaluateWhere(clause, row) {
  // Handle OR at the top level (split carefully, not inside quotes)
  const orParts = splitTopLevel(clause, /\bOR\b/i);
  if (orParts.length > 1) {
    return orParts.some(part => evaluateWhere(part.trim(), row));
  }

  // Handle AND
  const andParts = splitTopLevel(clause, /\bAND\b/i);
  if (andParts.length > 1) {
    return andParts.every(part => evaluateWhere(part.trim(), row));
  }

  // LIKE condition
  const likeM = clause.match(/^(\w+)\s+LIKE\s+'([^']*)'\s*$/i);
  if (likeM) {
    const col = likeM[1], pattern = likeM[2];
    const val = String(row[col] || '').toLowerCase();
    const regex = new RegExp('^' + pattern.toLowerCase().replace(/%/g, '.*').replace(/_/g, '.') + '$');
    return regex.test(val);
  }

  // Equality: col = 'val' or col = num
  const eqStrM = clause.match(/^(\w+)\s*=\s*'([^']*)'\s*$/i);
  if (eqStrM) return String(row[eqStrM[1]] || '') === eqStrM[2];

  const eqNumM = clause.match(/^(\w+)\s*=\s*(\d+)\s*$/i);
  if (eqNumM) return row[eqNumM[1]] == eqNumM[2];

  // Always-true literals: 1=1, 'x'='x', '1'='1'
  if (/^'[^']*'\s*=\s*'[^']*'$/i.test(clause)) {
    const parts = clause.match(/^'([^']*)'\s*=\s*'([^']*)'$/i);
    return parts[1] === parts[2];
  }
  if (/^\d+\s*=\s*\d+$/.test(clause.trim())) {
    const nums = clause.trim().match(/^(\d+)\s*=\s*(\d+)$/);
    return nums[1] === nums[2];
  }

  return false;
}

function splitTopLevel(str, regex) {
  // Split on keyword but not inside single quotes
  const parts = [];
  let current = '';
  let inStr = false;
  let i = 0;
  while (i < str.length) {
    if (str[i] === "'" && !inStr) { inStr = true; current += str[i++]; continue; }
    if (str[i] === "'" &&  inStr) { inStr = false; current += str[i++]; continue; }
    if (!inStr) {
      const rest = str.slice(i);
      const m = rest.match(regex);
      if (m && rest.toUpperCase().startsWith(m[0].toUpperCase())) {
        // Check it's a word boundary
        const before = current.trimEnd();
        parts.push(before);
        current = '';
        i += m[0].length;
        continue;
      }
    }
    current += str[i++];
  }
  parts.push(current);
  return parts.length > 1 ? parts : [str];
}

// ─── Vulnerable Mode ──────────────────────────────────────────────────────────

function runVuln() {
  const input = document.getElementById('vuln-input').value;

  // This is the vulnerable pattern: direct concatenation
  const sql = `SELECT * FROM products WHERE name LIKE '%${input}%'`;

  // Show the generated SQL with injection highlighted
  document.getElementById('vuln-sql').innerHTML = highlightVulnSQL(sql, input);

  const result = parseAndExecute(sql);

  const msgEl = document.getElementById('vuln-message');
  const resEl = document.getElementById('vuln-results');

  if (result.error) {
    resEl.innerHTML = '<div class="no-results">No rows (parse error)</div>';
    msgEl.innerHTML = `<div class="error-box">⚠ Engine error: ${result.error}</div>`;
    return;
  }

  // Detect if injection occurred (more rows than normal search, or different columns)
  const normalResult = safeQuery(input);
  const injected = result.rows.length > normalResult.rows.length || 
                   JSON.stringify(result.columns) !== JSON.stringify(normalResult.columns);

  msgEl.innerHTML = injected
    ? `<div class="error-box">💀 INJECTION SUCCEEDED — ${result.rows.length} row(s) returned. ` +
      `Normal search would return ${normalResult.rows.length}. Attacker accessed extra data.</div>`
    : '';

  resEl.innerHTML = renderTable(result.rows, result.columns, injected && result.rows.length > normalResult.rows.length ? normalResult.rows.length : -1);
}

// ─── Safe Mode ───────────────────────────────────────────────────────────────

function runSafe() {
  const input = document.getElementById('safe-input').value;

  // Template is fixed — compiled once. Input is NEVER parsed as SQL.
  const template = `SELECT * FROM products WHERE name LIKE ?`;
  // The parameter value — treated as a literal string, not SQL
  const paramValue = `%${input}%`;

  document.getElementById('safe-sql').innerHTML =
    `<span class="sql-keyword">SELECT</span> * <span class="sql-keyword">FROM</span> products ` +
    `<span class="sql-keyword">WHERE</span> name <span class="sql-keyword">LIKE</span> ` +
    `<span class="sql-param">?</span>  <span style="color:#8b949e;">← compiled query plan, structure fixed</span>`;

  document.getElementById('safe-param').innerHTML =
    `<span class="sql-param">$1 =</span> <span class="sql-string">"${escapeHtml(paramValue)}"</span>` +
    `  <span style="color:#8b949e;">← bound as string scalar, never re-parsed</span>`;

  const result = safeQuery(input);

  document.getElementById('safe-results').innerHTML = renderTable(result.rows, result.columns, -1);
  document.getElementById('safe-message').innerHTML =
    input.includes("'") || input.toLowerCase().includes('union') || input.toLowerCase().includes(' or ')
      ? `<div class="safe-note">✓ Injection payload detected in input but completely neutralized. ` +
        `The engine searched for a product literally named "${escapeHtml(input)}".</div>`
      : '';
}

function safeQuery(input) {
  // Parameterized: input is always treated as a literal LIKE pattern string
  // No SQL parsing of the input — we do a direct JS string match (equivalent to bound parameter)
  const pattern = input.toLowerCase();
  const rows = DB.products.filter(p => p.name.toLowerCase().includes(pattern));
  return { rows, columns: Object.keys(DB.products[0]) };
}

// ─── Rendering ────────────────────────────────────────────────────────────────

function renderTable(rows, columns, normalCount) {
  if (!rows || rows.length === 0) {
    return '<div class="no-results">0 rows returned</div>';
  }
  let html = `<table><tr>`;
  columns.forEach(c => { html += `<th>${escapeHtml(c)}</th>`; });
  html += '</tr>';
  rows.forEach((row, i) => {
    const isExtra = normalCount >= 0 && i >= normalCount;
    html += `<tr${isExtra ? ' class="highlight"' : ''}>`;
    columns.forEach(c => {
      html += `<td>${escapeHtml(String(row[c] !== undefined ? row[c] : ''))}</td>`;
    });
    html += '</tr>';
  });
  html += '</table>';
  if (normalCount >= 0 && rows.length > normalCount) {
    html += `<div style="color:#ffa657;font-size:0.75em;margin-top:6px;">` +
            `▲ Highlighted rows were not in the intended products result — leaked by injection</div>`;
  }
  return html;
}

function highlightVulnSQL(sql, input) {
  if (!input) {
    return `<span class="sql-keyword">SELECT</span> * <span class="sql-keyword">FROM</span> products ` +
           `<span class="sql-keyword">WHERE</span> name <span class="sql-keyword">LIKE</span> ` +
           `<span class="sql-string">'%%'</span>`;
  }
  // Find the injected portion and highlight it
  const safe_prefix = `SELECT * FROM products WHERE name LIKE '%`;
  const safe_suffix = `%'`;
  const injected_part = escapeHtml(input);

  return `<span class="sql-keyword">SELECT</span> * <span class="sql-keyword">FROM</span> products ` +
         `<span class="sql-keyword">WHERE</span> name <span class="sql-keyword">LIKE</span> ` +
         `<span class="sql-string">'%</span><span class="sql-injected">${injected_part}</span><span class="sql-string">%'</span>` +
         `  <span style="color:#8b949e;">← input embedded directly</span>`;
}

function escapeHtml(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function loadPreset(val) {
  document.getElementById('vuln-input').value = val;
  document.getElementById('safe-input').value = val;
  runVuln();
  runSafe();
}

// Init
runVuln();
runSafe();
</script>
</body>
</html>
```

## What makes this non-shallow:

**The parser actually works.** It handles:
- `OR` condition injection (bypasses WHERE filter)
- `--` comment truncation (drops the closing `%'`)
- `UNION SELECT` across tables (dumps the `users` table into product results)
- Always-true literals like `'x'='x'` and `1=1`

**The safe mode is mechanically correct.** It doesn't just "escape" — it never passes the input through the SQL parser at all. The query structure is compiled from the fixed template; the value is bound as a typed scalar afterward. That's what parameterization actually does.

**The highlighted rows** show exactly which rows came from injection vs. the legitimate query — so you can see the data leakage concretely.

Try the **UNION credential dump** preset first — it's the most instructive.
